'use client';

import React from 'react';

import {
  useImportExportActions,
  useImportExportData,
  useImportExportState,
} from '@/features/data-import-export/context/ImportExportContext';
import type { LabeledOptionDto } from '@/shared/contracts/base';
import type { IntegrationConnectionBasic } from '@/shared/contracts/integrations/domain';
import type { InventoryOption, Template } from '@/shared/contracts/integrations/import-export';
import { Label } from '@/shared/ui/primitives.public';
import { SelectSimple } from '@/shared/ui/forms-and-actions.public';

const BASE_CONNECTION_PLACEHOLDER_OPTION: LabeledOptionDto<string> = {
  value: '__none__',
  label: 'Select a connection...',
};

const DEFAULT_INVENTORY_PLACEHOLDER_OPTION: LabeledOptionDto<string> = {
  value: '__none__',
  label: 'Select default inventory...',
};

const EXPORT_TEMPLATE_PLACEHOLDER_OPTION: LabeledOptionDto<string> = {
  value: '__none__',
  label: 'No template (use defaults)',
};

export function ExportBaseConfigSection(): React.JSX.Element {
  const { baseConnections, inventories, exportTemplates, loadingExportTemplates } =
    useImportExportData();
  const {
    selectedBaseConnectionId,
    setSelectedBaseConnectionId,
    exportInventoryId,
    setExportInventoryId,
    exportWarehouseId,
    setExportWarehouseId,
    exportActiveTemplateId,
    setExportActiveTemplateId,
  } = useImportExportState();
  const { applyTemplate } = useImportExportActions();
  const baseConnectionOptions = React.useMemo(
    (): Array<LabeledOptionDto<string>> => [
      BASE_CONNECTION_PLACEHOLDER_OPTION,
      ...baseConnections.map((connection: IntegrationConnectionBasic) => ({
        value: connection.id,
        label: connection.name,
      })),
    ],
    [baseConnections]
  );
  const inventoryOptions = React.useMemo(
    (): Array<LabeledOptionDto<string>> => [
      DEFAULT_INVENTORY_PLACEHOLDER_OPTION,
      ...inventories.map((inv: InventoryOption) => ({ value: inv.id, label: inv.name })),
    ],
    [inventories]
  );
  const exportTemplateOptions = React.useMemo(
    (): Array<LabeledOptionDto<string>> => [
      EXPORT_TEMPLATE_PLACEHOLDER_OPTION,
      ...exportTemplates.map((tpl: Template) => ({ value: tpl.id, label: tpl.name })),
    ],
    [exportTemplates]
  );

  return (
    <div className='grid grid-cols-2 gap-4'>
      <div className='col-span-2'>
        <Label className='text-xs text-gray-400'>
          Default Base connection (OneClick + inventory tools)
        </Label>
        <div className='mt-2'>
          <SelectSimple
            size='sm'
            value={selectedBaseConnectionId || '__none__'}
            onValueChange={(v: string): void => {
              const nextConnectionId = v === '__none__' ? '' : v;
              if (nextConnectionId !== selectedBaseConnectionId) {
                if (exportInventoryId) setExportInventoryId('');
                if (exportWarehouseId) setExportWarehouseId('');
                if (exportActiveTemplateId) setExportActiveTemplateId('');
              }
              setSelectedBaseConnectionId(nextConnectionId);
            }}
            disabled={baseConnections.length === 0}
            options={baseConnectionOptions}
            placeholder={
              baseConnections.length === 0 ? 'No connections loaded' : 'Select a connection...'
            }
            triggerClassName='w-full bg-gray-900 border-border text-sm text-white h-9'
           ariaLabel={baseConnections.length === 0 ? 'No connections loaded' : 'Select a connection...'} title={baseConnections.length === 0 ? 'No connections loaded' : 'Select a connection...'}/>
        </div>
        <p className='mt-1 text-xs text-gray-500'>
          Used by Product List OneClick export and for loading inventories/warehouses.
        </p>
      </div>
      <div>
        <Label className='text-xs text-gray-400'>Default Inventory</Label>
        <div className='mt-2'>
          <SelectSimple
            size='sm'
            value={exportInventoryId || '__none__'}
            onValueChange={(v: string): void => setExportInventoryId(v === '__none__' ? '' : v)}
            disabled={inventories.length === 0 && !exportInventoryId}
            options={inventoryOptions}
            placeholder={
              inventories.length === 0
                ? exportInventoryId
                  ? `Saved inventory (${exportInventoryId})`
                  : 'No inventories loaded'
                : 'Select default inventory...'
            }
            triggerClassName='w-full bg-gray-900 border-border text-sm text-white h-9'
           ariaLabel={inventories.length === 0
                ? exportInventoryId
                  ? `Saved inventory (${exportInventoryId})`
                  : 'No inventories loaded'
                : 'Select default inventory...'} title={inventories.length === 0
                ? exportInventoryId
                  ? `Saved inventory (${exportInventoryId})`
                  : 'No inventories loaded'
                : 'Select default inventory...'}/>
        </div>
        <p className='mt-1 text-xs text-gray-500'>Default inventory for product exports</p>
      </div>

      <div>
        <Label className='text-xs text-gray-400'>Default Export Template</Label>
        <div className='mt-2'>
          <SelectSimple
            size='sm'
            value={exportActiveTemplateId || '__none__'}
            onValueChange={(nextId: string): void => {
              const val = nextId === '__none__' ? '' : nextId;
              const selected = exportTemplates.find((template: Template) => template.id === val);
              if (selected) {
                applyTemplate(selected, 'export');
              } else {
                setExportActiveTemplateId(val);
              }
            }}
            disabled={loadingExportTemplates || exportTemplates.length === 0}
            options={exportTemplateOptions}
            placeholder='No template (use defaults)'
            triggerClassName='w-full bg-gray-900 border-border text-sm text-white h-9'
           ariaLabel='No template (use defaults)' title='No template (use defaults)'/>
        </div>
        <p className='mt-1 text-xs text-gray-500'>Template for field mapping on export</p>
      </div>
    </div>
  );
}

import type {
  BaseImportDirectTarget,
  BaseImportMode,
  BaseImportRunResumePayload,
  BaseImportRunStartPayload,
} from '@/shared/contracts/integrations/base-com';
import type { ImportResponse } from '@/shared/contracts/integrations/import-export';
import type { ImageRetryPreset } from '@/shared/contracts/integrations/base';
import type { Toast } from '@/shared/contracts/ui/base';

import type { Dispatch, MutableRefObject, SetStateAction } from 'react';
import { logClientError } from '@/shared/utils/observability/client-error-logger';
import { buildImportResultToast } from '@/features/data-import-export/utils/import-run-feedback';

type RefetchResult<TData = unknown> = {
  data?: TData;
  error?: unknown;
};

type RefetchFn<TData = unknown> = () => Promise<RefetchResult<TData>>;

type ImportMutationLike = {
  mutateAsync: (payload: BaseImportRunStartPayload) => Promise<ImportResponse>;
};

type ResumeImportMutationLike = {
  mutateAsync: (payload: BaseImportRunResumePayload) => Promise<ImportResponse>;
};

type CancelImportMutationLike = {
  mutateAsync: () => Promise<ImportResponse>;
};

type SaveExportSettingsMutationLike = {
  mutateAsync: (payload: {
    exportActiveTemplateId: string;
    exportInventoryId: string;
    selectedBaseConnectionId: string;
    exportStockFallbackEnabled: boolean;
    imageRetryPresets: ImageRetryPreset[];
    exportWarehouseId: string;
  }) => Promise<unknown>;
};

type ClearInventoryMutationLike = {
  mutateAsync: () => Promise<unknown>;
};

type RefreshImportParameterCacheMutationLike = {
  mutateAsync: (payload: { inventoryId: string; connectionId: string }) => Promise<unknown>;
};

export type ImportExportRuntimeActionsArgs = {
  toast: Toast;
  setInventoriesEnabled: (enabled: boolean) => void;
  refetchInventories: RefetchFn<unknown[]>;
  inventoryId: string;
  selectedBaseConnectionId: string;
  refreshImportParameterCacheMutation: RefreshImportParameterCacheMutationLike;
  lastHydratedImportSchemaKey: MutableRefObject<string>;
  setWarehousesEnabled: (enabled: boolean) => void;
  refetchWarehouses: RefetchFn;
  setImportListEnabled: (enabled: boolean) => void;
  setImportListPage: (page: number) => void;
  setSelectedImportIds: Dispatch<SetStateAction<Set<string>>>;
  refetchImportList: RefetchFn;
  catalogId: string;
  importListEnabled: boolean;
  imageMode: 'links' | 'download';
  importMode: BaseImportMode;
  importDryRun: boolean;
  uniqueOnly: boolean;
  allowDuplicateSku: boolean;
  importTemplateId: string;
  limit: string;
  selectedImportIds: Set<string>;
  importMutation: ImportMutationLike;
  setLastResult: (res: ImportResponse | null) => void;
  setActiveImportRunId: (id: string) => void;
  setPollImportRun: (poll: boolean) => void;
  activeImportRunId: string;
  resumeImportRunMutation: ResumeImportMutationLike;
  cancelImportRunMutation: CancelImportMutationLike;
  saveExportSettingsMutation: SaveExportSettingsMutationLike;
  exportActiveTemplateId: string;
  exportInventoryId: string;
  exportWarehouseId: string;
  exportStockFallbackEnabled: boolean;
  imageRetryPresets: ImageRetryPreset[];
  setInventoryId: (id: string) => void;
  clearInventoryMutation: ClearInventoryMutationLike;
};

export type ImportExportRuntimeActions = {
  handleLoadInventories: () => Promise<void>;
  handleLoadWarehouses: () => Promise<void>;
  handleLoadImportList: () => Promise<void>;
  handleImport: (options?: { directTarget?: BaseImportDirectTarget | null }) => Promise<void>;
  handleResumeImport: () => Promise<void>;
  handleCancelImport: () => Promise<void>;
  handleDownloadImportReport: () => void;
  handleSaveExportSettings: () => Promise<void>;
  handleClearInventory: () => Promise<void>;
};

export const createImportExportRuntimeActions = ({
  toast,
  setInventoriesEnabled,
  refetchInventories,
  inventoryId,
  selectedBaseConnectionId,
  refreshImportParameterCacheMutation,
  lastHydratedImportSchemaKey,
  setWarehousesEnabled,
  refetchWarehouses,
  setImportListEnabled,
  setImportListPage,
  setSelectedImportIds,
  refetchImportList,
  catalogId,
  importListEnabled,
  imageMode,
  importMode,
  importDryRun,
  uniqueOnly,
  allowDuplicateSku,
  importTemplateId,
  limit,
  selectedImportIds,
  importMutation,
  setLastResult,
  setActiveImportRunId,
  setPollImportRun,
  activeImportRunId,
  resumeImportRunMutation,
  cancelImportRunMutation,
  saveExportSettingsMutation,
  exportActiveTemplateId,
  exportInventoryId,
  exportWarehouseId,
  exportStockFallbackEnabled,
  imageRetryPresets,
  setInventoryId,
  clearInventoryMutation,
}: ImportExportRuntimeActionsArgs): ImportExportRuntimeActions => {
  const handleLoadInventories = async (): Promise<void> => {
    setInventoriesEnabled(true);
    const result = await refetchInventories();
    if (result.error) {
      const message =
        result.error instanceof Error ? result.error.message : 'Failed to load inventories.';
      toast(message, { variant: 'error' });
      return;
    }
    const normalizeInventoryId = (value: unknown): string => {
      if (typeof value === 'string') return value.trim();
      if (typeof value === 'number' && Number.isFinite(value)) {
        return String(value);
      }
      return '';
    };
    const resultInventories = Array.isArray(result.data) ? result.data : [];
    const firstLoadedInventoryId = normalizeInventoryId(
      (resultInventories[0] as { inventory_id?: unknown; id?: unknown } | undefined)
        ?.inventory_id ??
        (resultInventories[0] as { inventory_id?: unknown; id?: unknown } | undefined)?.id
    );
    const selectedInventoryId = inventoryId.trim() || firstLoadedInventoryId;
    const selectedConnectionId = selectedBaseConnectionId.trim();
    if (selectedInventoryId && selectedConnectionId) {
      lastHydratedImportSchemaKey.current = '';
      void refreshImportParameterCacheMutation
        .mutateAsync({
          inventoryId: selectedInventoryId,
          connectionId: selectedConnectionId,
        })
        .catch(() => {
          // Keep inventory reload successful even if source schema hydration fails.
        });
    }
    toast('Inventories reloaded', { variant: 'success' });
  };

  const handleLoadWarehouses = async (): Promise<void> => {
    setWarehousesEnabled(true);
    const result = await refetchWarehouses();
    if (result.error) {
      const message =
        result.error instanceof Error ? result.error.message : 'Failed to load warehouses.';
      toast(message, { variant: 'error' });
      return;
    }
    toast('Warehouses reloaded', { variant: 'success' });
  };

  const handleLoadImportList = async (): Promise<void> => {
    setImportListEnabled(true);
    setImportListPage(1);
    setSelectedImportIds(new Set());
    const result = await refetchImportList();
    if (result.error) {
      const message =
        result.error instanceof Error ? result.error.message : 'Failed to load import list.';
      toast(message, { variant: 'error' });
      return;
    }
    toast('Import list reloaded', { variant: 'success' });
  };

  const handleImport = async (
    options?: { directTarget?: BaseImportDirectTarget | null }
  ): Promise<void> => {
    if (!inventoryId || !catalogId) {
      toast('Inventory and catalog are required', { variant: 'error' });
      return;
    }
    if (!selectedBaseConnectionId) {
      toast('Select a Base.com connection first.', { variant: 'error' });
      return;
    }
    const directTarget = options?.directTarget ?? null;
    if (importListEnabled && selectedImportIds.size === 0 && !directTarget) {
      toast('Select at least one product from the import list.', { variant: 'error' });
      return;
    }
    try {
      const selectedIds = Array.from(selectedImportIds);
      const importData: BaseImportRunStartPayload = {
        connectionId: selectedBaseConnectionId,
        inventoryId,
        catalogId,
        imageMode,
        mode: importMode,
        dryRun: importDryRun,
        uniqueOnly,
        allowDuplicateSku,
        requestId: `${Date.now()}`,
      };
      if (importTemplateId) importData.templateId = importTemplateId;
      if (limit !== 'all') importData.limit = Number(limit);
      if (directTarget) {
        importData.directTarget = directTarget;
      } else if (importListEnabled) {
        importData.selectedIds = selectedIds;
      } else if (selectedIds.length > 0) {
        importData.selectedIds = selectedIds;
      }

      const res = await importMutation.mutateAsync(importData);
      setLastResult(res);
      setActiveImportRunId(res.runId);
      const queuedLike = res.status === 'queued' || res.status === 'running';
      setPollImportRun(queuedLike);
      const importToast = buildImportResultToast(res, {
        kind: 'import',
        dryRun: importDryRun,
      });
      toast(importToast.message, importToast.toast);
    } catch (error: unknown) {
      logClientError(error);
      const message = error instanceof Error ? error.message : 'Import failed';
      toast(message, { variant: 'error' });
    }
  };

  const handleResumeImport = async (): Promise<void> => {
    if (!activeImportRunId) {
      toast('No import run selected for resume.', { variant: 'error' });
      return;
    }

    try {
      const resumed = await resumeImportRunMutation.mutateAsync({
        statuses: ['failed', 'pending'],
      });
      setLastResult(resumed);
      setPollImportRun(true);
      const resumeToast = buildImportResultToast(resumed, { kind: 'resume' });
      toast(resumeToast.message, resumeToast.toast);
    } catch (error: unknown) {
      logClientError(error);
      const message = error instanceof Error ? error.message : 'Failed to resume import run.';
      toast(message, { variant: 'error' });
    }
  };

  const handleCancelImport = async (): Promise<void> => {
    if (!activeImportRunId) {
      toast('No import run selected for cancel.', { variant: 'error' });
      return;
    }

    try {
      const canceled = await cancelImportRunMutation.mutateAsync();
      setLastResult(canceled);
      setPollImportRun(true);
      toast('Import cancel requested.', { variant: 'success' });
    } catch (error: unknown) {
      logClientError(error);
      const message = error instanceof Error ? error.message : 'Failed to request import cancel.';
      toast(message, { variant: 'error' });
    }
  };

  const handleDownloadImportReport = (): void => {
    if (!activeImportRunId) {
      toast('No import run selected.', { variant: 'error' });
      return;
    }
    const url = `/api/v2/integrations/imports/base/runs/${encodeURIComponent(
      activeImportRunId
    )}/report?format=csv`;
    window.open(url, '_blank', 'noopener,noreferrer');
  };

  const handleSaveExportSettings = async (): Promise<void> => {
    try {
      await saveExportSettingsMutation.mutateAsync({
        exportActiveTemplateId,
        exportInventoryId,
        selectedBaseConnectionId,
        exportStockFallbackEnabled,
        imageRetryPresets,
        exportWarehouseId,
      });
      toast('Export settings saved', { variant: 'success' });
    } catch (error: unknown) {
      logClientError(error);
      const message = error instanceof Error ? error.message : 'Save failed';
      toast(message, { variant: 'error' });
    }
  };

  const handleClearInventory = async (): Promise<void> => {
    setInventoryId('');
    try {
      await clearInventoryMutation.mutateAsync();
      toast('Inventory cleared.', { variant: 'success' });
    } catch (error) {
      logClientError(error);
      toast('Failed to clear inventory.', { variant: 'error' });
    }
  };

  return {
    handleLoadInventories,
    handleLoadWarehouses,
    handleLoadImportList,
    handleImport,
    handleResumeImport,
    handleCancelImport,
    handleDownloadImportReport,
    handleSaveExportSettings,
    handleClearInventory,
  };
};

'use client';

import { useMemo, useState, useEffect, type MutableRefObject } from 'react';

import {
  useInventories,
  useWarehouses,
  useImportList,
  useImportRun,
} from '@/features/data-import-export/hooks/useImportQueries';
import type {
  BaseImportDirectTargetType,
} from '@/shared/contracts/integrations/base-com';
import type { InventoryOption, ImportListItem, ImportRunDetail, WarehouseOption } from '@/shared/contracts/integrations/import-export';

export function useImportExportData({
  selectedBaseConnectionId,
  isBaseConnected,
  inventoriesEnabled,
  inventoryId,
  inventoryIdRef,
  setInventoryId,
  exportInventoryId,
  exportInventoryIdRef,
  setExportInventoryId,
  includeAllWarehouses,
  warehousesEnabled,
  catalogId,
  limit,
  uniqueOnly,
  importListPage,
  importListPageSize,
  importNameSearch,
  importDirectTargetType,
  importDirectTargetValue,
  importSkuSearch,
  importListEnabled,
  activeImportRunId,
  pollImportRun,
  setPollImportRun,
}: {
  selectedBaseConnectionId: string;
  isBaseConnected: boolean;
  inventoriesEnabled: boolean;
  inventoryId: string;
  inventoryIdRef: MutableRefObject<string>;
  setInventoryId: (id: string) => void;
  exportInventoryId: string;
  exportInventoryIdRef: MutableRefObject<string>;
  setExportInventoryId: (id: string) => void;
  includeAllWarehouses: boolean;
  warehousesEnabled: boolean;
  catalogId: string;
  limit: string;
  uniqueOnly: boolean;
  importListPage: number;
  importListPageSize: number;
  importNameSearch: string;
  importDirectTargetType: BaseImportDirectTargetType;
  importDirectTargetValue: string;
  importSkuSearch: string;
  importListEnabled: boolean;
  activeImportRunId: string;
  pollImportRun: boolean;
  setPollImportRun: (poll: boolean) => void;
}) {
  const normalizedSelectedBaseConnectionId = selectedBaseConnectionId.trim();
  const inventoriesQuery = useInventories(
    normalizedSelectedBaseConnectionId,
    inventoriesEnabled && isBaseConnected && Boolean(normalizedSelectedBaseConnectionId)
  );
  const inventories = useMemo<InventoryOption[]>(() => {
    const toText = (value: unknown): string => {
      if (typeof value === 'string') return value.trim();
      if (typeof value === 'number' && Number.isFinite(value)) return String(value);
      return '';
    };
    const rawInventories = Array.isArray(inventoriesQuery.data) ? inventoriesQuery.data : [];
    return rawInventories
      .map((inventory: unknown) => {
        const inv = inventory as { inventory_id?: unknown; id?: unknown; name?: unknown };
        return {
          id: toText(inv.inventory_id ?? inv.id),
          name: toText(inv.name),
        };
      })
      .filter((inventory: InventoryOption) => inventory.id.length > 0)
      .map((inventory: InventoryOption) => ({
        ...inventory,
        name: inventory.name || inventory.id,
      }));
  }, [inventoriesQuery.data]);
  const isFetchingInventories = inventoriesQuery.isFetching;
  const refetchInventories = inventoriesQuery.refetch;

  const [hasInitializedInventories, setHasInitializedInventories] = useState(false);
  useEffect(() => {
    if (inventories.length > 0 && !hasInitializedInventories) {
      const firstInventory = inventories[0];
      if (firstInventory?.id) {
        const firstInventoryId = firstInventory.id;
        const timer = setTimeout(() => {
          if (!inventoryIdRef.current.trim()) {
            setInventoryId(firstInventoryId);
          }
          if (!exportInventoryIdRef.current.trim()) {
            setExportInventoryId(firstInventoryId);
          }
          setHasInitializedInventories(true);
        }, 0);
        return (): void => clearTimeout(timer);
      }
    }
    return undefined;
  }, [
    inventories,
    inventoryId,
    exportInventoryId,
    inventoryIdRef,
    exportInventoryIdRef,
    hasInitializedInventories,
    setInventoryId,
    setExportInventoryId,
  ]);

  const warehousesQuery = useWarehouses(
    exportInventoryId,
    normalizedSelectedBaseConnectionId,
    includeAllWarehouses,
    warehousesEnabled &&
      isBaseConnected &&
      Boolean(normalizedSelectedBaseConnectionId) &&
      Boolean(exportInventoryId)
  );
  const warehousesData = warehousesQuery.data;
  const isFetchingWarehouses = warehousesQuery.isFetching;
  const refetchWarehouses = warehousesQuery.refetch;

  const warehouses: WarehouseOption[] = warehousesData?.warehouses ?? [];
  const allWarehouses: WarehouseOption[] = warehousesData?.allWarehouses ?? [];
  const normalizedImportDirectTargetValue = importDirectTargetValue.trim();
  const importDirectTarget =
    normalizedImportDirectTargetValue.length > 0
      ? {
          type: importDirectTargetType,
          value: normalizedImportDirectTargetValue,
        }
      : undefined;

  const importListQuery = useImportList(
    inventoryId,
    {
      connectionId: normalizedSelectedBaseConnectionId,
      catalogId,
      limit,
      uniqueOnly,
      page: importListPage,
      pageSize: importListPageSize,
      searchName: importNameSearch,
      directTarget: importDirectTarget,
      searchSku: importSkuSearch,
    },
    importListEnabled && isBaseConnected && Boolean(inventoryId) && Boolean(normalizedSelectedBaseConnectionId)
  );
  const importListData = importListQuery.data;
  const loadingImportList = importListQuery.isFetching;
  const refetchImportList = importListQuery.refetch;

  const importList: ImportListItem[] = useMemo(
    () => importListData?.products ?? [],
    [importListData]
  );
  const importListStats = useMemo(() => {
    if (!importListData) return null;
    return {
      total: importListData.total ?? 0,
      filtered: importListData.filtered ?? 0,
      available: importListData.available ?? importListData.filtered ?? 0,
      existing: importListData.existing ?? 0,
      skuDuplicates: importListData.skuDuplicates ?? 0,
      page: importListData.page ?? 1,
      pageSize: importListData.pageSize ?? importListPageSize,
      totalPages: importListData.totalPages ?? 1,
    };
  }, [importListData, importListPageSize]);

  const activeImportRunQuery = useImportRun(activeImportRunId, {
    enabled: Boolean(activeImportRunId),
    refetchInterval: pollImportRun ? 2000 : false,
    page: 1,
    pageSize: pollImportRun ? 250 : 1000,
    includeItems: true,
  });
  const activeImportRun = useMemo<ImportRunDetail | null>(() => {
    return activeImportRunQuery.data ?? null;
  }, [activeImportRunQuery.data]);
  const loadingImportRun = activeImportRunQuery.isFetching && Boolean(activeImportRunId);

  useEffect(() => {
    const status = activeImportRun?.run.status;
    if (!status) return;
    const isTerminal =
      status === 'completed' ||
      status === 'partial_success' ||
      status === 'failed' ||
      status === 'canceled';
    if (isTerminal) {
      setPollImportRun(false);
    }
  }, [activeImportRun?.run.status, setPollImportRun]);

  return {
    inventories,
    isFetchingInventories,
    refetchInventories,
    warehouses,
    allWarehouses,
    isFetchingWarehouses,
    refetchWarehouses,
    importList,
    loadingImportList,
    refetchImportList,
    importListStats,
    activeImportRun,
    loadingImportRun,
  };
}

'use client';

import { useEffect, useRef, type MutableRefObject } from 'react';

import { normalizeImageRetryPresets } from '@/features/data-import-export/utils/image-retry-presets';
import type { BaseActiveTemplatePreferenceResponse, BaseDefaultConnectionPreferenceResponse, BaseDefaultInventoryPreferenceResponse, BaseImageRetryPresetsResponse, BaseSampleProductResponse, BaseStockFallbackPreferenceResponse } from '@/shared/contracts/integrations/preferences';
import type { IntegrationConnectionBasic } from '@/shared/contracts/integrations/domain';
import type { ImageRetryPreset } from '@/shared/contracts/integrations/base';

export function useImportExportPreferences({
  lastImportTemplatePref,
  defaultExportInventoryPref,
  defaultConnectionPref,
  exportStockFallbackPref,
  imageRetryPresetsPref,
  sampleProductPref,
  baseConnections,
  importTemplateIdRef,
  inventoryIdRef,
  selectedBaseConnectionIdRef,
  setImportTemplateId,
  setExportInventoryId,
  setSelectedBaseConnectionId,
  setExportStockFallbackEnabled,
  setImageRetryPresets,
  setInventoryId,
}: {
  lastImportTemplatePref: BaseActiveTemplatePreferenceResponse | undefined | null;
  defaultExportInventoryPref: BaseDefaultInventoryPreferenceResponse | undefined | null;
  defaultConnectionPref: BaseDefaultConnectionPreferenceResponse | undefined | null;
  exportStockFallbackPref: BaseStockFallbackPreferenceResponse | undefined | null;
  imageRetryPresetsPref: BaseImageRetryPresetsResponse | undefined | null;
  sampleProductPref: BaseSampleProductResponse | undefined | null;
  baseConnections: IntegrationConnectionBasic[];
  importTemplateIdRef: MutableRefObject<string>;
  inventoryIdRef: MutableRefObject<string>;
  selectedBaseConnectionIdRef: MutableRefObject<string>;
  setImportTemplateId: (id: string) => void;
  setExportInventoryId: (id: string) => void;
  setSelectedBaseConnectionId: (id: string) => void;
  setExportStockFallbackEnabled: (enabled: boolean) => void;
  setImageRetryPresets: (presets: ImageRetryPreset[]) => void;
  setInventoryId: (id: string) => void;
}) {
  const hasInitializedPrefs = useRef(false);

  useEffect(() => {
    if (!hasInitializedPrefs.current) {
      const timer = setTimeout(() => {
        const liveImportTemplateId = importTemplateIdRef.current.trim();
        const liveSelectedBaseConnectionId = selectedBaseConnectionIdRef.current.trim();
        const liveInventoryId = inventoryIdRef.current.trim();

        if (!liveImportTemplateId && lastImportTemplatePref?.templateId) {
          setImportTemplateId(lastImportTemplatePref.templateId);
        }
        if (defaultExportInventoryPref?.inventoryId) {
          setExportInventoryId(defaultExportInventoryPref.inventoryId);
        }
        if (
          !liveSelectedBaseConnectionId &&
          defaultConnectionPref?.connectionId &&
          baseConnections.some(
            (c: IntegrationConnectionBasic) => c.id === defaultConnectionPref.connectionId
          )
        ) {
          setSelectedBaseConnectionId(defaultConnectionPref.connectionId);
        }
        if (exportStockFallbackPref?.enabled !== undefined) {
          setExportStockFallbackEnabled(exportStockFallbackPref.enabled);
        }
        if (imageRetryPresetsPref?.presets) {
          setImageRetryPresets(normalizeImageRetryPresets(imageRetryPresetsPref.presets));
        }
        if (!liveInventoryId && sampleProductPref?.inventoryId) {
          setInventoryId(sampleProductPref.inventoryId);
        }
        hasInitializedPrefs.current = true;
      }, 0);
      return (): void => clearTimeout(timer);
    }
    return undefined;
  }, [
    lastImportTemplatePref,
    defaultExportInventoryPref,
    defaultConnectionPref,
    exportStockFallbackPref,
    imageRetryPresetsPref,
    sampleProductPref,
    baseConnections,
    importTemplateIdRef,
    inventoryIdRef,
    selectedBaseConnectionIdRef,
    setImportTemplateId,
    setExportInventoryId,
    setSelectedBaseConnectionId,
    setExportStockFallbackEnabled,
    setImageRetryPresets,
    setInventoryId,
  ]);
}

'use client';

import { useCallback, useState } from 'react';

import { useTemplateMutation } from '@/features/data-import-export/hooks/useImportQueries';
import { defaultBaseImportParameterImportSettings, normalizeBaseImportParameterImportSettings } from '@/shared/contracts/integrations/parameter-import';
import { type ImportTemplateParameterImport } from '@/shared/contracts/integrations/templates';
import { type Template, type TemplateMapping } from '@/shared/contracts/integrations';
import type { Toast } from '@/shared/contracts/ui/base';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


const UNSUPPORTED_EXPORT_PARAMETER_SOURCE_PREFIX = 'parameter:';

const hasUnsupportedExportParameterSourceMapping = (mappings: TemplateMapping[]): boolean =>
  mappings.some((mapping: TemplateMapping) =>
    mapping.sourceKey.trim().toLowerCase().startsWith(UNSUPPORTED_EXPORT_PARAMETER_SOURCE_PREFIX)
  );

export function useImportExportTemplates({
  toast,
  importTemplates,
  exportTemplates,
  setTemplateScope,
}: {
  toast: Toast;
  importTemplates: Template[];
  exportTemplates: Template[];
  setTemplateScope: (scope: 'import' | 'export') => void;
}) {
  const [importActiveTemplateId, setImportActiveTemplateId] = useState('');
  const [exportActiveTemplateId, setExportActiveTemplateId] = useState('');
  const [importTemplateName, setImportTemplateName] = useState('');
  const [exportTemplateName, setExportTemplateName] = useState('');
  const [importTemplateDescription, setImportTemplateDescription] = useState('');
  const [exportTemplateDescription, setExportTemplateDescription] = useState('');
  const [importTemplateMappings, setImportTemplateMappings] = useState<TemplateMapping[]>([
    { sourceKey: '', targetField: '' },
  ]);
  const [importTemplateParameterImport, setImportTemplateParameterImport] =
    useState<ImportTemplateParameterImport>(defaultBaseImportParameterImportSettings);
  const [exportTemplateMappings, setExportTemplateMappings] = useState<TemplateMapping[]>([
    { sourceKey: '', targetField: '' },
  ]);
  const [exportImagesAsBase64, setExportImagesAsBase64] = useState(false);

  const applyTemplate = useCallback((template: Template, scope: 'import' | 'export'): void => {
    const nextMappings = template.mappings?.length
      ? template.mappings
      : [{ sourceKey: '', targetField: '' }];
    if (scope === 'import') {
      setImportActiveTemplateId(template.id);
      setImportTemplateName(template.name);
      setImportTemplateDescription(template.description ?? '');
      setImportTemplateMappings(nextMappings);
      setImportTemplateParameterImport(
        normalizeBaseImportParameterImportSettings(template.parameterImport)
      );
    } else {
      setExportActiveTemplateId(template.id);
      setExportTemplateName(template.name);
      setExportTemplateDescription(template.description ?? '');
      setExportTemplateMappings(nextMappings);
      setExportImagesAsBase64(template.exportImagesAsBase64 ?? false);
    }
  }, []);

  const saveImportTemplateMutation = useTemplateMutation('import', importActiveTemplateId);
  const saveExportTemplateMutation = useTemplateMutation('export', exportActiveTemplateId);
  const createImportTemplateMutation = useTemplateMutation('import');
  const createExportTemplateMutation = useTemplateMutation('export');

  const handleNewTemplate = (templateScope: 'import' | 'export'): void => {
    if (templateScope === 'import') {
      setImportActiveTemplateId('');
      setImportTemplateName('');
      setImportTemplateDescription('');
      setImportTemplateMappings([{ sourceKey: '', targetField: '' }]);
      setImportTemplateParameterImport(defaultBaseImportParameterImportSettings);
    } else {
      setExportActiveTemplateId('');
      setExportTemplateName('');
      setExportTemplateDescription('');
      setExportTemplateMappings([{ sourceKey: '', targetField: '' }]);
      setExportImagesAsBase64(false);
    }
  };

  const handleDuplicateTemplate = async (templateScope: 'import' | 'export'): Promise<void> => {
    const isImport = templateScope === 'import';
    const activeId = isImport ? importActiveTemplateId : exportActiveTemplateId;
    if (!activeId) {
      toast('Select a template to duplicate.', { variant: 'error' });
      return;
    }

    const sourceTemplate = (isImport ? importTemplates : exportTemplates).find(
      (template: Template) => template.id === activeId
    );
    if (!sourceTemplate) {
      toast('Selected template is missing.', { variant: 'error' });
      return;
    }

    const cleanMappings = (sourceTemplate.mappings ?? [])
      .map((mapping: TemplateMapping) => ({
        sourceKey: mapping.sourceKey?.trim() ?? '',
        targetField: mapping.targetField?.trim() ?? '',
      }))
      .filter((mapping: TemplateMapping) => mapping.sourceKey && mapping.targetField);

    if (!isImport && hasUnsupportedExportParameterSourceMapping(cleanMappings)) {
      toast(
        'Export template contains unsupported parameter source mappings. Use canonical text_fields.features.<name> mappings before duplicating.',
        { variant: 'error' }
      );
      return;
    }

    const mutation = isImport ? createImportTemplateMutation : createExportTemplateMutation;
    const duplicatedName = `${(sourceTemplate.name || 'Template').trim()} Copy`;

    try {
      const duplicated = (await mutation.mutateAsync({
        data: {
          name: duplicatedName,
          description: sourceTemplate.description?.trim() || undefined,
          mappings: cleanMappings,
          ...(isImport
            ? {
              parameterImport: normalizeBaseImportParameterImportSettings(
                sourceTemplate.parameterImport
              ),
            }
            : {
              exportImagesAsBase64: sourceTemplate.exportImagesAsBase64 ?? false,
            }),
        },
      })) as Template;
      applyTemplate(duplicated, isImport ? 'import' : 'export');
      toast('Template duplicated.', { variant: 'success' });
    } catch (error: unknown) {
      logClientError(error);
      const message = error instanceof Error ? error.message : 'Template duplicate failed';
      toast(message, { variant: 'error' });
    }
  };

  const handleCreateExportFromImportTemplate = async (): Promise<void> => {
    const activeImportTemplateId = importActiveTemplateId.trim();
    if (!activeImportTemplateId) {
      toast('Select an import template first.', { variant: 'error' });
      return;
    }

    const sourceTemplate = importTemplates.find(
      (template: Template) => template.id === activeImportTemplateId
    );
    if (!sourceTemplate) {
      toast('Selected import template is missing.', { variant: 'error' });
      return;
    }

    const cleanMappings = (sourceTemplate.mappings ?? [])
      .map((mapping: TemplateMapping) => ({
        sourceKey: mapping.sourceKey?.trim() ?? '',
        targetField: mapping.targetField?.trim() ?? '',
      }))
      .filter((mapping: TemplateMapping) => mapping.sourceKey && mapping.targetField);

    if (hasUnsupportedExportParameterSourceMapping(cleanMappings)) {
      toast(
        'Import template includes unsupported parameter source mappings for export copy. Update mappings to canonical fields first.',
        { variant: 'error' }
      );
      return;
    }

    const baseName = (sourceTemplate.name || 'Template').trim();
    const exportTemplateNameCandidate = baseName.toLowerCase().includes('export')
      ? baseName
      : `${baseName} Export`;

    try {
      const created = (await createExportTemplateMutation.mutateAsync({
        data: {
          name: exportTemplateNameCandidate,
          description: sourceTemplate.description?.trim() || undefined,
          mappings: cleanMappings,
          exportImagesAsBase64: false,
        },
      })) as Template;
      setTemplateScope('export');
      applyTemplate(created, 'export');
      toast('Export template created from import template.', {
        variant: 'success',
      });
    } catch (error: unknown) {
      logClientError(error);
      const message =
        error instanceof Error
          ? error.message
          : 'Failed to create export template from import template';
      toast(message, { variant: 'error' });
    }
  };

  const handleSaveTemplate = async (templateScope: 'import' | 'export'): Promise<void> => {
    const isImport = templateScope === 'import';
    const name = isImport ? importTemplateName : exportTemplateName;
    const desc = isImport ? importTemplateDescription : exportTemplateDescription;
    const mappings = isImport ? importTemplateMappings : exportTemplateMappings;
    const activeTemplateId = (isImport ? importActiveTemplateId : exportActiveTemplateId).trim();

    if (!name.trim()) {
      toast('Template name is required.', { variant: 'error' });
      return;
    }

    const cleanedMappings = mappings
      .map((m: TemplateMapping) => ({
        sourceKey: m.sourceKey.trim(),
        targetField: m.targetField.trim(),
      }))
      .filter((m: TemplateMapping) => m.sourceKey && m.targetField);

    if (!isImport && hasUnsupportedExportParameterSourceMapping(cleanedMappings)) {
      toast(
        'Export template mappings include unsupported "parameter:<id>" source keys. Use canonical text_fields.features.<name> source fields.',
        { variant: 'error' }
      );
      return;
    }

    const mutation = isImport
      ? activeTemplateId
        ? saveImportTemplateMutation
        : createImportTemplateMutation
      : activeTemplateId
        ? saveExportTemplateMutation
        : createExportTemplateMutation;

    try {
      const res = (await mutation.mutateAsync({
        data: {
          name: name.trim(),
          description: desc.trim() || undefined,
          mappings: cleanedMappings,
          ...(isImport
            ? {
              parameterImport: normalizeBaseImportParameterImportSettings(
                importTemplateParameterImport
              ),
            }
            : { exportImagesAsBase64 }),
        },
      })) as Template;
      applyTemplate(res, isImport ? 'import' : 'export');
      toast('Template saved.', { variant: 'success' });
    } catch (error: unknown) {
      logClientError(error);
      const message = error instanceof Error ? error.message : 'Template save failed';
      toast(message, { variant: 'error' });
    }
  };

  const handleDeleteTemplate = async (templateScope: 'import' | 'export'): Promise<void> => {
    const isImport = templateScope === 'import';
    const activeId = isImport ? importActiveTemplateId : exportActiveTemplateId;
    if (!activeId) return;

    const mutation = isImport ? saveImportTemplateMutation : saveExportTemplateMutation;
    try {
      await mutation.mutateAsync({ isDelete: true });
      handleNewTemplate(templateScope);
      toast('Template deleted.', { variant: 'success' });
    } catch (error: unknown) {
      logClientError(error);
      const message = error instanceof Error ? error.message : 'Template delete failed';
      toast(message, { variant: 'error' });
    }
  };

  return {
    importActiveTemplateId,
    setImportActiveTemplateId,
    exportActiveTemplateId,
    setExportActiveTemplateId,
    importTemplateName,
    setImportTemplateName,
    exportTemplateName,
    setExportTemplateName,
    importTemplateDescription,
    setImportTemplateDescription,
    exportTemplateDescription,
    setExportTemplateDescription,
    importTemplateMappings,
    setImportTemplateMappings,
    importTemplateParameterImport,
    setImportTemplateParameterImport,
    exportTemplateMappings,
    setExportTemplateMappings,
    exportImagesAsBase64,
    setExportImagesAsBase64,
    applyTemplate,
    saveImportTemplateMutation,
    saveExportTemplateMutation,
    createImportTemplateMutation,
    createExportTemplateMutation,
    handleNewTemplate,
    handleDuplicateTemplate,
    handleCreateExportFromImportTemplate,
    handleSaveTemplate,
    handleDeleteTemplate,
  };
}

'use client';

import { useEffect, useMemo, type MutableRefObject } from 'react';

import { useCatalogs } from '@/features/data-import-export/hooks/useImportQueries';
import type { CatalogOption } from '@/shared/contracts/integrations/import-export';
import type { IntegrationConnectionBasic, IntegrationWithConnections } from '@/shared/contracts/integrations/domain';
import { useIntegrationsWithConnections } from '@/shared/hooks/useIntegrationQueries';

interface ImportExportBootstrapResourcesParams {
  catalogId: string;
  catalogIdRef: MutableRefObject<string>;
  hasInitializedCatalog: MutableRefObject<boolean>;
  selectedBaseConnectionId: string;
  selectedBaseConnectionIdRef: MutableRefObject<string>;
  setBaseConnections: (connections: IntegrationConnectionBasic[]) => void;
  setCatalogId: (id: string) => void;
  setIsBaseConnected: (connected: boolean) => void;
  setSelectedBaseConnectionId: (id: string) => void;
}

interface ImportExportBootstrapResourcesResult {
  baseConnections: IntegrationConnectionBasic[];
  catalogsData: CatalogOption[];
  checkingIntegration: boolean;
  integrationsWithConnections: IntegrationWithConnections[];
  isBaseConnected: boolean;
  loadingCatalogs: boolean;
}

export function useImportExportBootstrapResources({
  catalogId,
  catalogIdRef,
  hasInitializedCatalog,
  selectedBaseConnectionId,
  selectedBaseConnectionIdRef,
  setBaseConnections,
  setCatalogId,
  setIsBaseConnected,
  setSelectedBaseConnectionId,
}: ImportExportBootstrapResourcesParams): ImportExportBootstrapResourcesResult {
  const { data: integrationsWithConnectionsData, isLoading: checkingIntegration } =
    useIntegrationsWithConnections();
  const integrationsWithConnections = useMemo(
    (): IntegrationWithConnections[] =>
      Array.isArray(integrationsWithConnectionsData) ? integrationsWithConnectionsData : [],
    [integrationsWithConnectionsData]
  );

  const [baseConnections, isBaseConnected] = useMemo(
    (): [IntegrationConnectionBasic[], boolean] => {
      const baseIntegration = integrationsWithConnections.find(
        (integration: IntegrationWithConnections): boolean =>
          ['baselinker', 'base-com', 'base'].includes(
            (integration.slug ?? '').trim().toLowerCase()
          )
      );
      const connections = baseIntegration?.connections ?? [];
      return [connections, connections.length > 0];
    },
    [integrationsWithConnections]
  );

  useEffect(() => {
    let timer: NodeJS.Timeout | null = null;
    timer = setTimeout(() => {
      setBaseConnections(baseConnections);
      setIsBaseConnected(isBaseConnected);
      const liveSelectedBaseConnectionId = selectedBaseConnectionIdRef.current.trim();
      if (checkingIntegration) {
        return;
      }
      if (baseConnections.length === 0) {
        if (liveSelectedBaseConnectionId) {
          setSelectedBaseConnectionId('');
        }
        return;
      }
      const hasSelected = baseConnections.some(
        (connection: IntegrationConnectionBasic) => connection.id === liveSelectedBaseConnectionId
      );
      if (!liveSelectedBaseConnectionId || !hasSelected) {
        setSelectedBaseConnectionId(baseConnections[0]?.id || '');
      }
    }, 0);
    return (): void => {
      if (timer) clearTimeout(timer);
    };
  }, [
    baseConnections,
    checkingIntegration,
    isBaseConnected,
    selectedBaseConnectionId,
    selectedBaseConnectionIdRef,
    setBaseConnections,
    setIsBaseConnected,
    setSelectedBaseConnectionId,
  ]);

  const catalogsQuery = useCatalogs();
  const catalogsData = useMemo<CatalogOption[]>(
    () => catalogsQuery.data || [],
    [catalogsQuery.data]
  );
  const loadingCatalogs = catalogsQuery.isLoading;

  useEffect(() => {
    let timer: NodeJS.Timeout | null = null;
    if (catalogsData.length > 0 && !catalogId) {
      const defaultCatalog = catalogsData.find((catalog: CatalogOption) => catalog.isDefault);
      const fallbackCatalog = defaultCatalog ?? catalogsData[0];
      if (fallbackCatalog) {
        timer = setTimeout(() => {
          if (!catalogIdRef.current.trim()) {
            setCatalogId(fallbackCatalog.id);
            hasInitializedCatalog.current = true;
          }
        }, 0);
      }
    }
    return (): void => {
      if (timer) clearTimeout(timer);
    };
  }, [catalogId, catalogIdRef, catalogsData, hasInitializedCatalog, setCatalogId]);

  return {
    baseConnections,
    catalogsData,
    checkingIntegration,
    integrationsWithConnections,
    isBaseConnected,
    loadingCatalogs,
  };
}

'use client';

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import {
  useCancelImportRunMutation,
  useClearInventoryMutation,
  useImportMutation,
  useResumeImportRunMutation,
  useSaveDefaultConnectionMutation,
  useSaveExportSettingsMutation,
} from '@/features/data-import-export/hooks/useImportQueries';
import { getDefaultImageRetryPresets } from '@/features/data-import-export/utils/image-retry-presets';
import {
  areImportResponsesEquivalent,
  resolveLiveImportResult,
} from '@/features/data-import-export/utils/import-run-feedback';
import type {
  BaseImportDirectTargetType,
  BaseImportMode,
} from '@/shared/contracts/integrations/base-com';
import type { DebugWarehouses, ImportResponse } from '@/shared/contracts/integrations/import-export';
import type { ImageRetryPreset } from '@/shared/contracts/integrations/base';
import { useToast } from '@/shared/ui/primitives.public';

import { createImportExportRuntimeActions } from './import-export-runtime-actions';
import { useImportExportRuntimeResources } from './useImportExportRuntimeResources';

import type {
  ImportExportActionsContextType,
  ImportExportDataContextType,
  ImportsPageTab,
  ImportExportStateContextType,
} from './ImportExportContext.types';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


interface ImportExportRuntimeResult {
  actionsValue: ImportExportActionsContextType;
  dataValue: ImportExportDataContextType;
  stateValue: ImportExportStateContextType;
}

const IMPORT_SETTINGS_STORAGE_KEY = 'product-import-runtime.v1';

type PersistedImportRuntimeState = {
  version: 1;
  saveImportSettings: true;
  importsPageTab: ImportsPageTab;
  selectedBaseConnectionId: string;
  inventoryId: string;
  catalogId: string;
  limit: string;
  imageMode: 'links' | 'download';
  importMode: BaseImportMode;
  importDryRun: boolean;
  uniqueOnly: boolean;
  allowDuplicateSku: boolean;
  importTemplateId: string;
  importNameSearch: string;
  importSkuSearch: string;
  importDirectTargetType: BaseImportDirectTargetType;
  importDirectTargetValue: string;
  importListPage: number;
  importListPageSize: number;
  importListEnabled: boolean;
};

type PersistedImportRuntimeStateInput = Omit<
  PersistedImportRuntimeState,
  'version' | 'saveImportSettings'
>;

const isBrowser = (): boolean =>
  typeof window !== 'undefined' && typeof window.localStorage !== 'undefined';

const DEFAULT_IMPORTS_PAGE_TAB: ImportsPageTab = 'import-list';

const normalizeImportsPageTab = (value: unknown): ImportsPageTab | null => {
  if (value === 'import') return 'import-list';
  if (
    value === 'import-list' ||
    value === 'import-settings' ||
    value === 'import-template'
  ) {
    return value;
  }
  return null;
};

const isImageMode = (value: unknown): value is 'links' | 'download' =>
  value === 'links' || value === 'download';

const isBaseImportMode = (value: unknown): value is BaseImportMode =>
  value === 'create_only' || value === 'upsert_on_base_id' || value === 'upsert_on_sku';

const buildPersistedImportRuntimeState = (
  value: PersistedImportRuntimeStateInput
): PersistedImportRuntimeState => ({
  version: 1,
  saveImportSettings: true,
  ...value,
});

const arePersistedImportRuntimeStatesEqual = (
  left: PersistedImportRuntimeState | null,
  right: PersistedImportRuntimeState | null
): boolean => JSON.stringify(left) === JSON.stringify(right);

const readPersistedImportRuntimeState = (): PersistedImportRuntimeState | null => {
  if (!isBrowser()) return null;
  try {
    const raw = window.localStorage.getItem(IMPORT_SETTINGS_STORAGE_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw) as Record<string, unknown>;
    if (parsed['version'] !== 1 || parsed['saveImportSettings'] !== true) return null;

    return {
      version: 1,
      saveImportSettings: true,
      importsPageTab: normalizeImportsPageTab(parsed['importsPageTab']) ?? DEFAULT_IMPORTS_PAGE_TAB,
      selectedBaseConnectionId:
        typeof parsed['selectedBaseConnectionId'] === 'string'
          ? parsed['selectedBaseConnectionId']
          : '',
      inventoryId: typeof parsed['inventoryId'] === 'string' ? parsed['inventoryId'] : '',
      catalogId: typeof parsed['catalogId'] === 'string' ? parsed['catalogId'] : '',
      limit: typeof parsed['limit'] === 'string' ? parsed['limit'] : 'all',
      imageMode: isImageMode(parsed['imageMode']) ? parsed['imageMode'] : 'download',
      importMode: isBaseImportMode(parsed['importMode'])
        ? parsed['importMode']
        : 'upsert_on_base_id',
      importDryRun: parsed['importDryRun'] === true,
      uniqueOnly: parsed['uniqueOnly'] !== false,
      allowDuplicateSku: parsed['allowDuplicateSku'] === true,
      importTemplateId: typeof parsed['importTemplateId'] === 'string' ? parsed['importTemplateId'] : '',
      importNameSearch:
        typeof parsed['importNameSearch'] === 'string' ? parsed['importNameSearch'] : '',
      importSkuSearch:
        typeof parsed['importSkuSearch'] === 'string' ? parsed['importSkuSearch'] : '',
      importDirectTargetType:
        parsed['importDirectTargetType'] === 'sku' ? 'sku' : 'base_product_id',
      importDirectTargetValue:
        typeof parsed['importDirectTargetValue'] === 'string'
          ? parsed['importDirectTargetValue']
          : '',
      importListPage:
        typeof parsed['importListPage'] === 'number' && parsed['importListPage'] > 0
          ? Math.floor(parsed['importListPage'])
          : 1,
      importListPageSize:
        typeof parsed['importListPageSize'] === 'number' && parsed['importListPageSize'] > 0
          ? Math.floor(parsed['importListPageSize'])
          : 25,
      importListEnabled: parsed['importListEnabled'] === true,
    };
  } catch (error: unknown) {
    logClientError(error);
    try {
      window.localStorage.removeItem(IMPORT_SETTINGS_STORAGE_KEY);
    } catch {
      // Ignore cleanup failures after malformed payloads.
    }
    return null;
  }
};

const writePersistedImportRuntimeState = (value: PersistedImportRuntimeState | null): void => {
  if (!isBrowser()) return;
  try {
    if (!value) {
      window.localStorage.removeItem(IMPORT_SETTINGS_STORAGE_KEY);
      return;
    }
    window.localStorage.setItem(IMPORT_SETTINGS_STORAGE_KEY, JSON.stringify(value));
  } catch (error: unknown) {
    logClientError(error);
  }
};

export function useImportExportRuntime(): ImportExportRuntimeResult {
  const { toast } = useToast();

  const [saveImportSettings, setSaveImportSettings] = useState(false);
  const [savedImportSettingsSnapshot, setSavedImportSettingsSnapshot] =
    useState<PersistedImportRuntimeState | null>(null);
  const [importsPageTab, setImportsPageTab] = useState<ImportsPageTab>(DEFAULT_IMPORTS_PAGE_TAB);
  const [showAllWarehouses, setShowAllWarehouses] = useState(false);
  const [includeAllWarehouses, setIncludeAllWarehouses] = useState(false);
  const [inventoryId, setInventoryId] = useState('');
  const [exportInventoryId, setExportInventoryId] = useState('');
  const [exportWarehouseId, setExportWarehouseId] = useState('');
  const [catalogId, setCatalogId] = useState('');
  const [limit, setLimit] = useState('all');
  const [imageMode, setImageMode] = useState<'links' | 'download'>('download');
  const [importMode, setImportMode] = useState<BaseImportMode>('upsert_on_base_id');
  const [importDryRun, setImportDryRun] = useState(false);
  const [lastResult, setLastResult] = useState<ImportResponse | null>(null);
  const [activeImportRunId, setActiveImportRunId] = useState('');
  const [pollImportRun, setPollImportRun] = useState(false);
  const [importNameSearch, setImportNameSearch] = useState('');
  const [importSkuSearch, setImportSkuSearch] = useState('');
  const [importDirectTargetType, setImportDirectTargetType] =
    useState<BaseImportDirectTargetType>('base_product_id');
  const [importDirectTargetValue, setImportDirectTargetValue] = useState('');
  const [selectedImportIds, setSelectedImportIds] = useState<Set<string>>(new Set());
  const [uniqueOnly, setUniqueOnly] = useState(true);
  const [allowDuplicateSku, setAllowDuplicateSku] = useState(false);
  const [templateScope, setTemplateScope] = useState<'import' | 'export'>('import');
  const [importListPage, setImportListPage] = useState(1);
  const [importListPageSize, setImportListPageSize] = useState(25);
  const [importListEnabled, setImportListEnabled] = useState(false);
  const [inventoriesEnabled, setInventoriesEnabled] = useState(false);
  const [warehousesEnabled, setWarehousesEnabled] = useState(false);
  const [importTemplateId, setImportTemplateId] = useState('');
  const [exportStockFallbackEnabled, setExportStockFallbackEnabled] = useState(false);
  const [imageRetryPresets, setImageRetryPresets] = useState<ImageRetryPreset[]>(
    getDefaultImageRetryPresets()
  );
  const [isBaseConnected, setIsBaseConnected] = useState(false);
  const [baseConnections, setBaseConnections] = useState<
    ImportExportDataContextType['baseConnections']
  >([]);
  const [selectedBaseConnectionId, setSelectedBaseConnectionId] = useState('');
  const [debugWarehouses, setDebugWarehouses] = useState<DebugWarehouses | null>(null);

  const lastSavedImportTemplateId = useRef<string | null>(null);
  const lastSavedImportActiveTemplateId = useRef<string | null>(null);
  const lastSavedExportActiveTemplateId = useRef<string | null>(null);
  const hasInitializedCatalog = useRef(false);
  const lastHydratedImportActiveTemplateScope = useRef('');
  const lastHydratedExportActiveTemplateScope = useRef('');
  const skipNextImportActiveTemplatePersist = useRef(false);
  const skipNextExportActiveTemplatePersist = useRef(false);
  const lastHydratedImportSchemaKey = useRef('');
  const importSettingsHydrated = useRef(false);
  const selectedBaseConnectionIdRef = useRef(selectedBaseConnectionId);
  const inventoryIdRef = useRef(inventoryId);
  const exportInventoryIdRef = useRef(exportInventoryId);
  const catalogIdRef = useRef(catalogId);
  const importTemplateIdRef = useRef(importTemplateId);

  selectedBaseConnectionIdRef.current = selectedBaseConnectionId;
  inventoryIdRef.current = inventoryId;
  exportInventoryIdRef.current = exportInventoryId;
  catalogIdRef.current = catalogId;
  importTemplateIdRef.current = importTemplateId;

  const {
    activeImportRun,
    allWarehouses,
    catalogsData,
    checkingIntegration,
    exportTemplates,
    importTemplates,
    importList,
    importListStats,
    importSourceFieldValues,
    importSourceFields,
    integrationsWithConnections,
    inventories,
    isFetchingInventories,
    isFetchingWarehouses,
    loadingCatalogs,
    loadingExportTemplates,
    loadingImportList,
    loadingImportRun,
    loadingImportSourceFields,
    loadingImportTemplates,
    refreshImportParameterCacheMutation,
    refetchImportList,
    refetchInventories,
    refetchWarehouses,
    templates,
    warehouses,
  } = useImportExportRuntimeResources({
    activeImportRunId,
    catalogId,
    catalogIdRef,
    exportInventoryId,
    exportInventoryIdRef,
    hasInitializedCatalog,
    importListEnabled,
    importListPage,
    importListPageSize,
    importNameSearch,
    importDirectTargetType,
    importDirectTargetValue,
    importSkuSearch,
    importTemplateId,
    importTemplateIdRef,
    inventoriesEnabled,
    inventoryId,
    inventoryIdRef,
    includeAllWarehouses,
    lastHydratedExportActiveTemplateScope,
    lastHydratedImportActiveTemplateScope,
    lastHydratedImportSchemaKey,
    lastSavedExportActiveTemplateId,
    lastSavedImportActiveTemplateId,
    lastSavedImportTemplateId,
    limit,
    pollImportRun,
    selectedBaseConnectionId,
    selectedBaseConnectionIdRef,
    setBaseConnections,
    setCatalogId,
    setExportInventoryId,
    setExportStockFallbackEnabled,
    setImageRetryPresets,
    setImportTemplateId,
    setInventoryId,
    setIsBaseConnected,
    setPollImportRun,
    setSelectedBaseConnectionId,
    setTemplateScope,
    skipNextExportActiveTemplatePersist,
    skipNextImportActiveTemplatePersist,
    toast,
    uniqueOnly,
    warehousesEnabled,
  });

  const importMutation = useImportMutation();
  const resumeImportRunMutation = useResumeImportRunMutation(activeImportRunId);
  const cancelImportRunMutation = useCancelImportRunMutation(activeImportRunId);
  const saveDefaultConnectionMutation = useSaveDefaultConnectionMutation();
  const saveExportSettingsMutation = useSaveExportSettingsMutation();
  const clearInventoryMutation = useClearInventoryMutation();

  const currentPersistedImportRuntimeState = useMemo<PersistedImportRuntimeState>(
    () =>
      buildPersistedImportRuntimeState({
        importsPageTab,
        selectedBaseConnectionId,
        inventoryId,
        catalogId,
        limit,
        imageMode,
        importMode,
        importDryRun,
        uniqueOnly,
        allowDuplicateSku,
        importTemplateId,
        importNameSearch,
        importSkuSearch,
        importDirectTargetType,
        importDirectTargetValue,
        importListPage,
        importListPageSize,
        importListEnabled,
      }),
    [
      allowDuplicateSku,
      catalogId,
      imageMode,
      importDryRun,
      importListEnabled,
      importListPage,
      importListPageSize,
      importMode,
      importNameSearch,
      importDirectTargetType,
      importDirectTargetValue,
      importSkuSearch,
      importTemplateId,
      importsPageTab,
      inventoryId,
      limit,
      selectedBaseConnectionId,
      uniqueOnly,
    ]
  );

  const hasUnsavedImportSettingsChanges = useMemo(
    () =>
      saveImportSettings &&
      savedImportSettingsSnapshot !== null &&
      !arePersistedImportRuntimeStatesEqual(
        savedImportSettingsSnapshot,
        currentPersistedImportRuntimeState
      ),
    [currentPersistedImportRuntimeState, saveImportSettings, savedImportSettingsSnapshot]
  );

  useEffect(() => {
    const persisted = readPersistedImportRuntimeState();
    if (persisted) {
      setSaveImportSettings(true);
      setSavedImportSettingsSnapshot(persisted);
      setImportsPageTab(persisted.importsPageTab);
      setSelectedBaseConnectionId(persisted.selectedBaseConnectionId);
      setInventoryId(persisted.inventoryId);
      setCatalogId(persisted.catalogId);
      setLimit(persisted.limit);
      setImageMode(persisted.imageMode);
      setImportMode(persisted.importMode);
      setImportDryRun(persisted.importDryRun);
      setUniqueOnly(persisted.uniqueOnly);
      setAllowDuplicateSku(persisted.allowDuplicateSku);
      setImportTemplateId(persisted.importTemplateId);
      setImportNameSearch(persisted.importNameSearch);
      setImportSkuSearch(persisted.importSkuSearch);
      setImportDirectTargetType(persisted.importDirectTargetType);
      setImportDirectTargetValue(persisted.importDirectTargetValue);
      setImportListPage(persisted.importListPage);
      setImportListPageSize(persisted.importListPageSize);
      setImportListEnabled(persisted.importListEnabled);
      if (persisted.selectedBaseConnectionId || persisted.inventoryId) {
        setInventoriesEnabled(true);
      }
    } else {
      setSaveImportSettings(false);
      setSavedImportSettingsSnapshot(null);
    }
    importSettingsHydrated.current = true;
  }, []);

  useEffect(() => {
    if (!saveImportSettings || !selectedBaseConnectionId || baseConnections.length === 0) return;
    const hasSelectedConnection = baseConnections.some(
      (connection) => connection.id === selectedBaseConnectionId
    );
    if (!hasSelectedConnection) {
      setSelectedBaseConnectionId('');
      setInventoryId('');
      setImportTemplateId('');
      setImportListEnabled(false);
    }
  }, [baseConnections, saveImportSettings, selectedBaseConnectionId]);

  useEffect(() => {
    if (!saveImportSettings || !inventoryId || inventories.length === 0) return;
    const hasInventory = inventories.some((inventory) => inventory.id === inventoryId);
    if (!hasInventory) {
      setInventoryId('');
      setImportListEnabled(false);
    }
  }, [inventories, inventoryId, saveImportSettings]);

  useEffect(() => {
    if (!saveImportSettings || !catalogId || catalogsData.length === 0) return;
    const hasCatalog = catalogsData.some((catalog) => catalog.id === catalogId);
    if (!hasCatalog) {
      setCatalogId('');
    }
  }, [catalogId, catalogsData, saveImportSettings]);

  useEffect(() => {
    if (!saveImportSettings || !importTemplateId || importTemplates.length === 0) return;
    const hasTemplate = importTemplates.some((template) => template.id === importTemplateId);
    if (!hasTemplate) {
      setImportTemplateId('');
    }
  }, [importTemplateId, importTemplates, saveImportSettings]);

  const activeRunBusy =
    activeImportRun?.run.status === 'queued' || activeImportRun?.run.status === 'running';

  useEffect(() => {
    if (!lastResult) return;
    const syncedResult = resolveLiveImportResult(lastResult, activeImportRun?.run ?? null);
    if (!areImportResponsesEquivalent(lastResult, syncedResult)) {
      setLastResult(syncedResult);
    }
  }, [activeImportRun?.run, lastResult]);

  const refetchInventoriesSafe = useCallback(async () => {
    const result = await refetchInventories();
    return {
      data: Array.isArray(result.data) ? result.data : [],
      error: result.error,
    };
  }, [refetchInventories]);

  const refetchWarehousesSafe = useCallback(async () => {
    const result = await refetchWarehouses();
    return {
      data: result.data,
      error: result.error,
    };
  }, [refetchWarehouses]);

  const refetchImportListSafe = useCallback(async () => {
    const result = await refetchImportList();
    return {
      data: result.data,
      error: result.error,
    };
  }, [refetchImportList]);

  const runtimeActions = createImportExportRuntimeActions({
    toast,
    setInventoriesEnabled,
    refetchInventories: refetchInventoriesSafe,
    inventoryId,
    selectedBaseConnectionId,
    refreshImportParameterCacheMutation,
    lastHydratedImportSchemaKey,
    setWarehousesEnabled,
    refetchWarehouses: refetchWarehousesSafe,
    setImportListEnabled,
    setImportListPage,
    setSelectedImportIds,
    refetchImportList: refetchImportListSafe,
    catalogId,
    importListEnabled,
    imageMode,
    importMode,
    importDryRun,
    uniqueOnly,
    allowDuplicateSku,
    importTemplateId,
    limit,
    selectedImportIds,
    importMutation,
    setLastResult,
    setActiveImportRunId,
    setPollImportRun,
    activeImportRunId,
    resumeImportRunMutation,
    cancelImportRunMutation,
    saveExportSettingsMutation,
    exportActiveTemplateId: templates.exportActiveTemplateId,
    exportInventoryId,
    exportWarehouseId,
    exportStockFallbackEnabled,
    imageRetryPresets,
    setInventoryId,
    clearInventoryMutation,
  });

  const handleSaveDefaultBaseConnection = useCallback(async (): Promise<void> => {
    const normalizedConnectionId = selectedBaseConnectionId.trim();
    if (!normalizedConnectionId) {
      toast('Select a Base.com connection first.', { variant: 'error' });
      return;
    }

    try {
      await saveDefaultConnectionMutation.mutateAsync({
        connectionId: normalizedConnectionId,
      });
      toast('Default Base.com connection saved.', { variant: 'success' });
    } catch (error: unknown) {
      logClientError(error);
      const message =
        error instanceof Error ? error.message : 'Failed to save default Base.com connection.';
      toast(message, { variant: 'error' });
    }
  }, [saveDefaultConnectionMutation, selectedBaseConnectionId, toast]);

  const handleSaveImportSettings = useCallback(async (): Promise<void> => {
    if (!importSettingsHydrated.current) return;
    writePersistedImportRuntimeState(currentPersistedImportRuntimeState);
    setSavedImportSettingsSnapshot(currentPersistedImportRuntimeState);
    setSaveImportSettings(true);
    toast('Import settings saved for this browser.', { variant: 'success' });
  }, [currentPersistedImportRuntimeState, toast]);

  const handleClearSavedImportSettings = useCallback(async (): Promise<void> => {
    writePersistedImportRuntimeState(null);
    setSavedImportSettingsSnapshot(null);
    setSaveImportSettings(false);
    toast('Saved import settings cleared.', { variant: 'success' });
  }, [toast]);

  const importing =
    importMutation.isPending ||
    resumeImportRunMutation.isPending ||
    cancelImportRunMutation.isPending ||
    activeRunBusy;
  const savingDefaultConnection = saveDefaultConnectionMutation.isPending;
  const savingExportSettings = saveExportSettingsMutation.isPending;
  const savingImportTemplate =
    templates.saveImportTemplateMutation.isPending ||
    templates.createImportTemplateMutation.isPending;
  const savingExportTemplate =
    templates.saveExportTemplateMutation.isPending ||
    templates.createExportTemplateMutation.isPending;

  const stateValue = useMemo<ImportExportStateContextType>(
    () => ({
      saveImportSettings,
      hasUnsavedImportSettingsChanges,
      importsPageTab,
      setImportsPageTab,
      inventoryId,
      setInventoryId,
      exportInventoryId,
      setExportInventoryId,
      exportWarehouseId,
      setExportWarehouseId,
      catalogId,
      setCatalogId,
      limit,
      setLimit,
      imageMode,
      setImageMode,
      importMode,
      setImportMode,
      importDryRun,
      setImportDryRun,
      allowDuplicateSku,
      setAllowDuplicateSku,
      uniqueOnly,
      setUniqueOnly,
      importTemplateId,
      setImportTemplateId,
      ...templates,
      exportImagesAsBase64: templates.exportImagesAsBase64,
      setExportImagesAsBase64: templates.setExportImagesAsBase64,
      exportStockFallbackEnabled,
      setExportStockFallbackEnabled,
      imageRetryPresets,
      setImageRetryPresets,
      selectedBaseConnectionId,
      setSelectedBaseConnectionId,
      importNameSearch,
      setImportNameSearch,
      importSkuSearch,
      setImportSkuSearch,
      importDirectTargetType,
      setImportDirectTargetType,
      importDirectTargetValue,
      setImportDirectTargetValue,
      importListPage,
      setImportListPage,
      importListPageSize,
      setImportListPageSize,
      importListEnabled,
      setImportListEnabled,
      selectedImportIds,
      setSelectedImportIds,
      activeImportRunId,
      setActiveImportRunId,
      templateScope,
      setTemplateScope,
      showAllWarehouses,
      setShowAllWarehouses,
      includeAllWarehouses,
      setIncludeAllWarehouses,
      debugWarehouses,
      setDebugWarehouses,
    }),
    [
      allowDuplicateSku,
      catalogId,
      hasUnsavedImportSettingsChanges,
      debugWarehouses,
      exportInventoryId,
      exportStockFallbackEnabled,
      exportWarehouseId,
      imageMode,
      imageRetryPresets,
      importDryRun,
      importListEnabled,
      importListPage,
      importListPageSize,
      importMode,
      importNameSearch,
      importDirectTargetType,
      importDirectTargetValue,
      importSkuSearch,
      importTemplateId,
      importsPageTab,
      includeAllWarehouses,
      inventoryId,
      limit,
      activeImportRunId,
      saveImportSettings,
      selectedBaseConnectionId,
      selectedImportIds,
      showAllWarehouses,
      templateScope,
      templates,
      uniqueOnly,
    ]
  );

  const dataValue = useMemo<ImportExportDataContextType>(
    () => ({
      integrationsWithConnections,
      checkingIntegration,
      isBaseConnected,
      baseConnections,
      catalogsData,
      loadingCatalogs,
      importTemplates,
      loadingImportTemplates,
      exportTemplates,
      loadingExportTemplates,
      inventories,
      isFetchingInventories,
      warehouses,
      allWarehouses,
      isFetchingWarehouses,
      importList,
      loadingImportList,
      importListStats,
      lastResult,
      activeImportRunId,
      activeImportRun,
      loadingImportRun,
      importSourceFields,
      importSourceFieldValues,
      loadingImportSourceFields,
    }),
    [
      activeImportRun,
      activeImportRunId,
      allWarehouses,
      baseConnections,
      catalogsData,
      checkingIntegration,
      exportTemplates,
      importList,
      importListStats,
      importSourceFieldValues,
      importSourceFields,
      integrationsWithConnections,
      inventories,
      isBaseConnected,
      isFetchingInventories,
      isFetchingWarehouses,
      lastResult,
      loadingCatalogs,
      loadingExportTemplates,
      loadingImportList,
      loadingImportRun,
      loadingImportSourceFields,
      loadingImportTemplates,
      importTemplates,
      warehouses,
    ]
  );

  const actionsValue = useMemo<ImportExportActionsContextType>(
    () => ({
      ...runtimeActions,
      handleSaveImportSettings,
      handleClearSavedImportSettings,
      handleSaveDefaultBaseConnection,
      handleNewTemplate: (scope) => templates.handleNewTemplate(scope ?? templateScope),
      handleDuplicateTemplate: (scope) => templates.handleDuplicateTemplate(scope ?? templateScope),
      handleCreateExportFromImportTemplate: templates.handleCreateExportFromImportTemplate,
      handleSaveTemplate: (scope) => templates.handleSaveTemplate(scope ?? templateScope),
      handleDeleteTemplate: (scope) => templates.handleDeleteTemplate(scope ?? templateScope),
      applyTemplate: templates.applyTemplate,
      importing,
      savingDefaultConnection,
      savingExportSettings,
      savingImportTemplate,
      savingExportTemplate,
    }),
    [
      handleClearSavedImportSettings,
      handleSaveImportSettings,
      handleSaveDefaultBaseConnection,
      importing,
      runtimeActions,
      savingDefaultConnection,
      savingExportSettings,
      savingExportTemplate,
      savingImportTemplate,
      templateScope,
      templates,
    ]
  );

  return {
    actionsValue,
    dataValue,
    stateValue,
  };
}

import type { BaseImportDirectTargetType } from '@/shared/contracts/integrations/base-com';
import type { ImageRetryPreset } from '@/shared/contracts/integrations/base';
import type { IntegrationConnectionBasic } from '@/shared/contracts/integrations/domain';
import type { Toast } from '@/shared/contracts/ui/base';

import { useImportExportData as useImportExportDataSource } from './import-export/useImportExportData';
import { useImportExportBootstrapResources } from './useImportExportBootstrapResources';
import { useImportExportTemplateResources } from './useImportExportTemplateResources';

import type {
  Dispatch,
  MutableRefObject,
  SetStateAction,
} from 'react';

interface ImportExportRuntimeResourcesParams {
  activeImportRunId: string;
  catalogId: string;
  exportInventoryId: string;
  exportInventoryIdRef: MutableRefObject<string>;
  hasInitializedCatalog: MutableRefObject<boolean>;
  importListEnabled: boolean;
  importListPage: number;
  importListPageSize: number;
  importNameSearch: string;
  importDirectTargetType: BaseImportDirectTargetType;
  importDirectTargetValue: string;
  importSkuSearch: string;
  importTemplateId: string;
  importTemplateIdRef: MutableRefObject<string>;
  inventoriesEnabled: boolean;
  inventoryId: string;
  inventoryIdRef: MutableRefObject<string>;
  includeAllWarehouses: boolean;
  lastHydratedExportActiveTemplateScope: MutableRefObject<string>;
  lastHydratedImportActiveTemplateScope: MutableRefObject<string>;
  lastHydratedImportSchemaKey: MutableRefObject<string>;
  lastSavedExportActiveTemplateId: MutableRefObject<string | null>;
  lastSavedImportActiveTemplateId: MutableRefObject<string | null>;
  lastSavedImportTemplateId: MutableRefObject<string | null>;
  limit: string;
  pollImportRun: boolean;
  selectedBaseConnectionId: string;
  selectedBaseConnectionIdRef: MutableRefObject<string>;
  catalogIdRef: MutableRefObject<string>;
  setBaseConnections: (connections: IntegrationConnectionBasic[]) => void;
  setCatalogId: (id: string) => void;
  setExportInventoryId: (id: string) => void;
  setExportStockFallbackEnabled: (enabled: boolean) => void;
  setImageRetryPresets: Dispatch<SetStateAction<ImageRetryPreset[]>>;
  setImportTemplateId: (id: string) => void;
  setInventoryId: (id: string) => void;
  setIsBaseConnected: (connected: boolean) => void;
  setPollImportRun: (poll: boolean) => void;
  setSelectedBaseConnectionId: (id: string) => void;
  setTemplateScope: (scope: 'import' | 'export') => void;
  skipNextExportActiveTemplatePersist: MutableRefObject<boolean>;
  skipNextImportActiveTemplatePersist: MutableRefObject<boolean>;
  toast: Toast;
  uniqueOnly: boolean;
  warehousesEnabled: boolean;
}

interface ImportExportRuntimeResourcesResult {
  activeImportRun: ReturnType<typeof useImportExportDataSource>['activeImportRun'];
  allWarehouses: ReturnType<typeof useImportExportDataSource>['allWarehouses'];
  baseConnections: IntegrationConnectionBasic[];
  catalogsData: ReturnType<typeof useImportExportBootstrapResources>['catalogsData'];
  checkingIntegration: boolean;
  exportTemplates: ReturnType<typeof useImportExportTemplateResources>['exportTemplates'];
  importList: ReturnType<typeof useImportExportDataSource>['importList'];
  importListStats: ReturnType<typeof useImportExportDataSource>['importListStats'];
  importSourceFieldValues: ReturnType<
    typeof useImportExportTemplateResources
  >['importSourceFieldValues'];
  importSourceFields: ReturnType<typeof useImportExportTemplateResources>['importSourceFields'];
  importTemplates: ReturnType<typeof useImportExportTemplateResources>['importTemplates'];
  integrationsWithConnections: ReturnType<
    typeof useImportExportBootstrapResources
  >['integrationsWithConnections'];
  inventories: ReturnType<typeof useImportExportDataSource>['inventories'];
  isBaseConnected: boolean;
  isFetchingInventories: boolean;
  isFetchingWarehouses: boolean;
  loadingCatalogs: boolean;
  loadingExportTemplates: boolean;
  loadingImportList: boolean;
  loadingImportRun: boolean;
  loadingImportSourceFields: boolean;
  loadingImportTemplates: boolean;
  refreshImportParameterCacheMutation: ReturnType<
    typeof useImportExportTemplateResources
  >['refreshImportParameterCacheMutation'];
  refetchImportList: ReturnType<typeof useImportExportDataSource>['refetchImportList'];
  refetchInventories: ReturnType<typeof useImportExportDataSource>['refetchInventories'];
  refetchWarehouses: ReturnType<typeof useImportExportDataSource>['refetchWarehouses'];
  templates: ReturnType<typeof useImportExportTemplateResources>['templates'];
  warehouses: ReturnType<typeof useImportExportDataSource>['warehouses'];
}

export function useImportExportRuntimeResources(
  params: ImportExportRuntimeResourcesParams
): ImportExportRuntimeResourcesResult {
  const {
    activeImportRunId,
    catalogId,
    exportInventoryId,
    exportInventoryIdRef,
    hasInitializedCatalog,
    importListEnabled,
    importListPage,
    importListPageSize,
    importNameSearch,
    importDirectTargetType,
    importDirectTargetValue,
    importSkuSearch,
    importTemplateId,
    importTemplateIdRef,
    inventoriesEnabled,
    inventoryId,
    inventoryIdRef,
    includeAllWarehouses,
    lastHydratedExportActiveTemplateScope,
    lastHydratedImportActiveTemplateScope,
    lastHydratedImportSchemaKey,
    lastSavedExportActiveTemplateId,
    lastSavedImportActiveTemplateId,
    lastSavedImportTemplateId,
    limit,
    pollImportRun,
    selectedBaseConnectionId,
    selectedBaseConnectionIdRef,
    catalogIdRef,
    setBaseConnections,
    setCatalogId,
    setExportInventoryId,
    setExportStockFallbackEnabled,
    setImageRetryPresets,
    setImportTemplateId,
    setInventoryId,
    setIsBaseConnected,
    setPollImportRun,
    setSelectedBaseConnectionId,
    setTemplateScope,
    skipNextExportActiveTemplatePersist,
    skipNextImportActiveTemplatePersist,
    toast,
    uniqueOnly,
    warehousesEnabled,
  } = params;
  const {
    baseConnections,
    catalogsData,
    checkingIntegration,
    integrationsWithConnections,
    isBaseConnected,
    loadingCatalogs,
  } = useImportExportBootstrapResources({
    catalogId,
    catalogIdRef,
    hasInitializedCatalog,
    selectedBaseConnectionId,
    selectedBaseConnectionIdRef,
    setBaseConnections,
    setCatalogId,
    setIsBaseConnected,
    setSelectedBaseConnectionId,
  });

  const {
    exportTemplates,
    importSourceFieldValues,
    importSourceFields,
    importTemplates,
    loadingExportTemplates,
    loadingImportSourceFields,
    loadingImportTemplates,
    refreshImportParameterCacheMutation,
    templates,
  } = useImportExportTemplateResources({
    baseConnections,
    exportInventoryId,
    importTemplateId,
    importTemplateIdRef,
    inventoryId,
    inventoryIdRef,
    isBaseConnected,
    lastHydratedExportActiveTemplateScope,
    lastHydratedImportActiveTemplateScope,
    lastHydratedImportSchemaKey,
    lastSavedExportActiveTemplateId,
    lastSavedImportActiveTemplateId,
    lastSavedImportTemplateId,
    selectedBaseConnectionId,
    selectedBaseConnectionIdRef,
    setExportInventoryId,
    setExportStockFallbackEnabled,
    setImageRetryPresets,
    setImportTemplateId,
    setInventoryId,
    setSelectedBaseConnectionId,
    setTemplateScope,
    skipNextExportActiveTemplatePersist,
    skipNextImportActiveTemplatePersist,
    toast,
  });

  const data = useImportExportDataSource({
    selectedBaseConnectionId,
    isBaseConnected,
    inventoriesEnabled,
    inventoryId,
    inventoryIdRef,
    setInventoryId,
    exportInventoryId,
    exportInventoryIdRef,
    setExportInventoryId,
    includeAllWarehouses,
    warehousesEnabled,
    catalogId,
    limit,
    uniqueOnly,
    importListPage,
    importListPageSize,
    importNameSearch,
    importDirectTargetType,
    importDirectTargetValue,
    importSkuSearch,
    importListEnabled,
    activeImportRunId,
    pollImportRun,
    setPollImportRun,
  });

  return {
    activeImportRun: data.activeImportRun,
    allWarehouses: data.allWarehouses,
    baseConnections,
    catalogsData,
    checkingIntegration,
    exportTemplates,
    importList: data.importList,
    importListStats: data.importListStats,
    importSourceFieldValues,
    importSourceFields,
    importTemplates,
    integrationsWithConnections,
    inventories: data.inventories,
    isBaseConnected,
    isFetchingInventories: data.isFetchingInventories,
    isFetchingWarehouses: data.isFetchingWarehouses,
    loadingCatalogs,
    loadingExportTemplates,
    loadingImportList: data.loadingImportList,
    loadingImportRun: data.loadingImportRun,
    loadingImportSourceFields,
    loadingImportTemplates,
    refreshImportParameterCacheMutation,
    refetchImportList: data.refetchImportList,
    refetchInventories: data.refetchInventories,
    refetchWarehouses: data.refetchWarehouses,
    templates,
    warehouses: data.warehouses,
  };
}

'use client';

import {
  useEffect,
  useMemo,
  type Dispatch,
  type MutableRefObject,
  type SetStateAction,
} from 'react';

import {
  useImportParameterCache,
  useImportPreference,
  useRefreshImportParameterCacheMutation,
  useSavePreferenceMutation,
  useTemplates,
} from '@/features/data-import-export/hooks/useImportQueries';
import { getDefaultImageRetryPresets } from '@/features/data-import-export/utils/image-retry-presets';
import type { BaseActiveTemplatePreferenceResponse, BaseDefaultConnectionPreferenceResponse, BaseDefaultInventoryPreferenceResponse, BaseImageRetryPresetsResponse, BaseSampleProductResponse, BaseStockFallbackPreferenceResponse } from '@/shared/contracts/integrations/preferences';
import type { ImageRetryPreset } from '@/shared/contracts/integrations/base';
import type { ImportParameterCacheResponse } from '@/shared/contracts/integrations/base-com';
import type { IntegrationConnectionBasic } from '@/shared/contracts/integrations/domain';
import type { Template } from '@/shared/contracts/integrations/import-export';
import { defaultBaseImportParameterImportSettings } from '@/shared/contracts/integrations/parameter-import';
import type { Toast } from '@/shared/contracts/ui/base';

import { useImportExportPreferences } from './import-export/useImportExportPreferences';
import { useImportExportTemplates } from './import-export/useImportExportTemplates';

const buildScopedTemplatePreferenceEndpoint = (
  endpoint: string,
  connectionId: string,
  inventoryId: string
): string => {
  const params = new URLSearchParams({
    connectionId,
    inventoryId,
  });
  return `${endpoint}?${params.toString()}`;
};

interface ImportExportTemplateResourcesParams {
  baseConnections: IntegrationConnectionBasic[];
  exportInventoryId: string;
  importTemplateId: string;
  importTemplateIdRef: MutableRefObject<string>;
  inventoryId: string;
  inventoryIdRef: MutableRefObject<string>;
  isBaseConnected: boolean;
  lastHydratedExportActiveTemplateScope: MutableRefObject<string>;
  lastHydratedImportActiveTemplateScope: MutableRefObject<string>;
  lastHydratedImportSchemaKey: MutableRefObject<string>;
  lastSavedExportActiveTemplateId: MutableRefObject<string | null>;
  lastSavedImportActiveTemplateId: MutableRefObject<string | null>;
  lastSavedImportTemplateId: MutableRefObject<string | null>;
  selectedBaseConnectionId: string;
  selectedBaseConnectionIdRef: MutableRefObject<string>;
  setExportInventoryId: (id: string) => void;
  setExportStockFallbackEnabled: (enabled: boolean) => void;
  setImageRetryPresets: Dispatch<SetStateAction<ImageRetryPreset[]>>;
  setImportTemplateId: (id: string) => void;
  setInventoryId: (id: string) => void;
  setSelectedBaseConnectionId: (id: string) => void;
  setTemplateScope: (scope: 'import' | 'export') => void;
  skipNextExportActiveTemplatePersist: MutableRefObject<boolean>;
  skipNextImportActiveTemplatePersist: MutableRefObject<boolean>;
  toast: Toast;
}

interface ImportExportTemplateResourcesResult {
  exportTemplates: Template[];
  importSourceFieldValues: Record<string, string>;
  importSourceFields: string[];
  importTemplates: Template[];
  loadingExportTemplates: boolean;
  loadingImportSourceFields: boolean;
  loadingImportTemplates: boolean;
  refreshImportParameterCacheMutation: ReturnType<typeof useRefreshImportParameterCacheMutation>;
  templates: ReturnType<typeof useImportExportTemplates>;
}

export function useImportExportTemplateResources({
  baseConnections,
  exportInventoryId,
  importTemplateId,
  importTemplateIdRef,
  inventoryId,
  inventoryIdRef,
  isBaseConnected,
  lastHydratedExportActiveTemplateScope,
  lastHydratedImportActiveTemplateScope,
  lastHydratedImportSchemaKey,
  lastSavedExportActiveTemplateId,
  lastSavedImportActiveTemplateId,
  lastSavedImportTemplateId,
  selectedBaseConnectionId,
  selectedBaseConnectionIdRef,
  setExportInventoryId,
  setExportStockFallbackEnabled,
  setImageRetryPresets,
  setImportTemplateId,
  setInventoryId,
  setSelectedBaseConnectionId,
  setTemplateScope,
  skipNextExportActiveTemplatePersist,
  skipNextImportActiveTemplatePersist,
  toast,
}: ImportExportTemplateResourcesParams): ImportExportTemplateResourcesResult {
  const { data: importTemplates = [], isLoading: loadingImportTemplates } = useTemplates('import');
  const { data: exportTemplates = [], isLoading: loadingExportTemplates } = useTemplates('export');

  const normalizedSelectedBaseConnectionId = selectedBaseConnectionId.trim();
  const normalizedImportInventoryId = inventoryId.trim();
  const normalizedExportInventoryId = exportInventoryId.trim();
  const importTemplateScopeReady =
    normalizedSelectedBaseConnectionId.length > 0 && normalizedImportInventoryId.length > 0;
  const exportTemplateScopeReady =
    normalizedSelectedBaseConnectionId.length > 0 && normalizedExportInventoryId.length > 0;
  const importTemplateScopeKey = importTemplateScopeReady
    ? `${normalizedSelectedBaseConnectionId}:${normalizedImportInventoryId}`
    : '';
  const exportTemplateScopeKey = exportTemplateScopeReady
    ? `${normalizedSelectedBaseConnectionId}:${normalizedExportInventoryId}`
    : '';

  const { data: lastImportTemplatePref } = useImportPreference<BaseActiveTemplatePreferenceResponse>(
    'last-template',
    '/api/v2/integrations/imports/base/last-template'
  );
  const { data: activeImportTemplatePref, isFetched: hasFetchedActiveImportTemplatePref } =
    useImportPreference<BaseActiveTemplatePreferenceResponse>(
      `active-template:${importTemplateScopeKey || 'none'}`,
      importTemplateScopeReady
        ? buildScopedTemplatePreferenceEndpoint(
          '/api/v2/integrations/imports/base/active-template',
          normalizedSelectedBaseConnectionId,
          normalizedImportInventoryId
        )
        : '/api/v2/integrations/imports/base/active-template',
      { enabled: importTemplateScopeReady }
    );
  const { data: activeExportTemplatePref, isFetched: hasFetchedActiveExportTemplatePref } =
    useImportPreference<BaseActiveTemplatePreferenceResponse>(
      `export-active-template:${exportTemplateScopeKey || 'none'}`,
      exportTemplateScopeReady
        ? buildScopedTemplatePreferenceEndpoint(
          '/api/v2/integrations/exports/base/active-template',
          normalizedSelectedBaseConnectionId,
          normalizedExportInventoryId
        )
        : '/api/v2/integrations/exports/base/active-template',
      { enabled: exportTemplateScopeReady }
    );
  const { data: defaultExportInventoryPref } =
    useImportPreference<BaseDefaultInventoryPreferenceResponse>(
      'default-inventory',
      '/api/v2/integrations/exports/base/default-inventory'
    );
  const { data: defaultConnectionPref } =
    useImportPreference<BaseDefaultConnectionPreferenceResponse>(
      'default-connection',
      '/api/v2/integrations/exports/base/default-connection'
    );
  const { data: exportStockFallbackPref } = useImportPreference<BaseStockFallbackPreferenceResponse>(
    'stock-fallback',
    '/api/v2/integrations/exports/base/stock-fallback'
  );
  const { data: imageRetryPresetsPref } = useImportPreference<BaseImageRetryPresetsResponse>(
    'image-retry-presets',
    '/api/v2/integrations/exports/base/image-retry-presets',
    { fallback: { presets: getDefaultImageRetryPresets() } }
  );
  const { data: sampleProductPref } = useImportPreference<BaseSampleProductResponse>(
    'sample-product',
    '/api/v2/integrations/imports/base/sample-product'
  );

  useImportExportPreferences({
    lastImportTemplatePref,
    defaultExportInventoryPref,
    defaultConnectionPref,
    exportStockFallbackPref,
    imageRetryPresetsPref,
    sampleProductPref,
    baseConnections,
    importTemplateIdRef,
    inventoryIdRef,
    selectedBaseConnectionIdRef,
    setImportTemplateId,
    setExportInventoryId,
    setSelectedBaseConnectionId,
    setExportStockFallbackEnabled,
    setImageRetryPresets,
    setInventoryId,
  });

  const templates = useImportExportTemplates({
    toast,
    importTemplates,
    exportTemplates,
    setTemplateScope,
  });
  const { applyTemplate } = templates;

  useEffect(() => {
    if (!importTemplateScopeReady) return;
    if (!hasFetchedActiveImportTemplatePref || importTemplates.length === 0) return;
    if (lastHydratedImportActiveTemplateScope.current === importTemplateScopeKey) return;
    const preferredTemplateId = activeImportTemplatePref?.templateId?.trim() || '';
    const preferred = preferredTemplateId
      ? (importTemplates.find((template: Template) => template.id === preferredTemplateId) ?? null)
      : null;
    skipNextImportActiveTemplatePersist.current = true;
    if (preferred) {
      applyTemplate(preferred, 'import');
    } else {
      templates.setImportActiveTemplateId('');
      templates.setImportTemplateName('');
      templates.setImportTemplateDescription('');
      templates.setImportTemplateMappings([{ sourceKey: '', targetField: '' }]);
      templates.setImportTemplateParameterImport(defaultBaseImportParameterImportSettings);
    }
    lastHydratedImportActiveTemplateScope.current = importTemplateScopeKey;
  }, [
    activeImportTemplatePref,
    applyTemplate,
    hasFetchedActiveImportTemplatePref,
    importTemplateScopeKey,
    importTemplateScopeReady,
    importTemplates,
    lastHydratedImportActiveTemplateScope,
    skipNextImportActiveTemplatePersist,
    templates,
  ]);

  useEffect(() => {
    if (!exportTemplateScopeReady) return;
    if (!hasFetchedActiveExportTemplatePref || exportTemplates.length === 0) return;
    if (lastHydratedExportActiveTemplateScope.current === exportTemplateScopeKey) return;
    const preferredTemplateId = activeExportTemplatePref?.templateId?.trim() || '';
    const preferred = preferredTemplateId
      ? (exportTemplates.find((template: Template) => template.id === preferredTemplateId) ?? null)
      : null;
    skipNextExportActiveTemplatePersist.current = true;
    if (preferred) {
      applyTemplate(preferred, 'export');
    } else {
      templates.setExportActiveTemplateId('');
      templates.setExportTemplateName('');
      templates.setExportTemplateDescription('');
      templates.setExportTemplateMappings([{ sourceKey: '', targetField: '' }]);
      templates.setExportImagesAsBase64(false);
    }
    lastHydratedExportActiveTemplateScope.current = exportTemplateScopeKey;
  }, [
    activeExportTemplatePref,
    applyTemplate,
    exportTemplateScopeKey,
    exportTemplateScopeReady,
    exportTemplates,
    hasFetchedActiveExportTemplatePref,
    lastHydratedExportActiveTemplateScope,
    skipNextExportActiveTemplatePersist,
    templates,
  ]);

  const savePreferenceMutation = useSavePreferenceMutation();
  const refreshImportParameterCacheMutation = useRefreshImportParameterCacheMutation();
  const importParameterCacheQuery = useImportParameterCache(isBaseConnected);
  const importParameterCache = useMemo<ImportParameterCacheResponse | null>(
    () => (importParameterCacheQuery.data as ImportParameterCacheResponse) ?? null,
    [importParameterCacheQuery.data]
  );

  useEffect(() => {
    const normalized = importTemplateId.trim() || null;
    const persisted = lastImportTemplatePref?.templateId?.trim() || null;
    if (persisted === normalized) return;
    if (lastSavedImportTemplateId.current === normalized) return;
    lastSavedImportTemplateId.current = normalized;
    savePreferenceMutation.mutate({
      endpoint: '/api/v2/integrations/imports/base/last-template',
      data: normalized ? { templateId: normalized } : {},
    });
  }, [
    importTemplateId,
    lastImportTemplatePref?.templateId,
    lastSavedImportTemplateId,
    savePreferenceMutation,
  ]);

  useEffect(() => {
    if (!importTemplateScopeReady) return;
    if (!hasFetchedActiveImportTemplatePref) return;
    if (lastHydratedImportActiveTemplateScope.current !== importTemplateScopeKey) return;
    if (skipNextImportActiveTemplatePersist.current) {
      skipNextImportActiveTemplatePersist.current = false;
      return;
    }
    const normalized = templates.importActiveTemplateId.trim() || null;
    const persisted = activeImportTemplatePref?.templateId?.trim() || null;
    if (persisted === normalized) return;
    const saveSignature = `${importTemplateScopeKey}:${normalized ?? ''}`;
    if (lastSavedImportActiveTemplateId.current === saveSignature) return;
    lastSavedImportActiveTemplateId.current = saveSignature;
    savePreferenceMutation.mutate({
      endpoint: '/api/v2/integrations/imports/base/active-template',
      data: {
        templateId: normalized,
        connectionId: normalizedSelectedBaseConnectionId,
        inventoryId: normalizedImportInventoryId,
      },
    });
  }, [
    activeImportTemplatePref?.templateId,
    hasFetchedActiveImportTemplatePref,
    importTemplateScopeKey,
    importTemplateScopeReady,
    lastHydratedImportActiveTemplateScope,
    lastSavedImportActiveTemplateId,
    normalizedImportInventoryId,
    normalizedSelectedBaseConnectionId,
    savePreferenceMutation,
    skipNextImportActiveTemplatePersist,
    templates.importActiveTemplateId,
  ]);

  useEffect(() => {
    if (!exportTemplateScopeReady) return;
    if (!hasFetchedActiveExportTemplatePref) return;
    if (lastHydratedExportActiveTemplateScope.current !== exportTemplateScopeKey) return;
    if (skipNextExportActiveTemplatePersist.current) {
      skipNextExportActiveTemplatePersist.current = false;
      return;
    }
    const normalized = templates.exportActiveTemplateId.trim() || null;
    const persisted = activeExportTemplatePref?.templateId?.trim() || null;
    if (persisted === normalized) return;
    const saveSignature = `${exportTemplateScopeKey}:${normalized ?? ''}`;
    if (lastSavedExportActiveTemplateId.current === saveSignature) return;
    lastSavedExportActiveTemplateId.current = saveSignature;
    savePreferenceMutation.mutate({
      endpoint: '/api/v2/integrations/exports/base/active-template',
      data: {
        templateId: normalized,
        connectionId: normalizedSelectedBaseConnectionId,
        inventoryId: normalizedExportInventoryId,
      },
    });
  }, [
    activeExportTemplatePref?.templateId,
    exportTemplateScopeKey,
    exportTemplateScopeReady,
    hasFetchedActiveExportTemplatePref,
    lastHydratedExportActiveTemplateScope,
    lastSavedExportActiveTemplateId,
    normalizedExportInventoryId,
    normalizedSelectedBaseConnectionId,
    savePreferenceMutation,
    skipNextExportActiveTemplatePersist,
    templates.exportActiveTemplateId,
  ]);

  const importSourceFields = useMemo<string[]>((): string[] => {
    const rawKeys =
      importParameterCache && Array.isArray(importParameterCache.keys)
        ? (importParameterCache.keys as unknown[])
        : [];
    const normalized = rawKeys
      .map((key: unknown): string => (typeof key === 'string' ? key.trim() : ''))
      .filter((key: string): boolean => key.length > 0);
    return Array.from(new Set(normalized)).sort((left: string, right: string) =>
      left.localeCompare(right)
    );
  }, [importParameterCache]);

  const importSourceFieldValues = useMemo<Record<string, string>>(() => {
    const rawValues = importParameterCache?.values;
    if (!rawValues || typeof rawValues !== 'object') return {};
    const normalized: Record<string, string> = {};
    Object.entries(rawValues).forEach(([key, value]: [string, unknown]) => {
      const normalizedKey = key.trim();
      if (!normalizedKey || typeof value !== 'string') return;
      const normalizedValue = value.trim();
      if (!normalizedValue) return;
      normalized[normalizedKey] = normalizedValue;
    });
    return normalized;
  }, [importParameterCache]);

  useEffect(() => {
    const normalizedInventoryId = inventoryId.trim();
    const normalizedConnectionId = selectedBaseConnectionId.trim();
    if (!normalizedInventoryId || !normalizedConnectionId || !isBaseConnected) {
      return;
    }
    const schemaCacheKey = `${normalizedConnectionId}:${normalizedInventoryId}`;
    const cachedInventoryId =
      typeof importParameterCache?.inventoryId === 'string'
        ? importParameterCache.inventoryId.trim()
        : '';
    if (cachedInventoryId === normalizedInventoryId && importSourceFields.length > 0) {
      lastHydratedImportSchemaKey.current = schemaCacheKey;
      return;
    }
    if (lastHydratedImportSchemaKey.current === schemaCacheKey) return;
    if (refreshImportParameterCacheMutation.isPending) return;
    lastHydratedImportSchemaKey.current = schemaCacheKey;
    void refreshImportParameterCacheMutation
      .mutateAsync({
        inventoryId: normalizedInventoryId,
        connectionId: normalizedConnectionId,
      })
      .catch(() => {
        // Source fields remain optional; users can still enter custom keys.
      });
  }, [
    importParameterCache?.inventoryId,
    importSourceFields.length,
    inventoryId,
    isBaseConnected,
    lastHydratedImportSchemaKey,
    refreshImportParameterCacheMutation,
    selectedBaseConnectionId,
  ]);

  return {
    exportTemplates,
    importSourceFieldValues,
    importSourceFields,
    importTemplates,
    loadingExportTemplates,
    loadingImportSourceFields:
      importParameterCacheQuery.isFetching || refreshImportParameterCacheMutation.isPending,
    loadingImportTemplates,
    refreshImportParameterCacheMutation,
    templates,
  };
}

'use client';

import React, { useState } from 'react';

import { useCsvImportMutation } from '@/features/data-import-export/hooks/useImportMutations';
import { Button, useToast } from '@/shared/ui/primitives.public';
import { FileUploadButton } from '@/shared/ui/forms-and-actions.public';
import { PanelHeader } from '@/shared/ui/templates.public';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


const CSVImportPage = (): React.JSX.Element => {
  const { toast } = useToast();
  const [file, setFile] = useState<File | null>(null);
  const importMutation = useCsvImportMutation();

  const handleFileChange = (files: File[]): void => {
    setFile(files[0] || null);
  };

  const handleSubmit = async (helpers?: {
    reportProgress: (loaded: number, total?: number) => void;
  }): Promise<void> => {
    if (!file) {
      toast('Please select a file', { variant: 'error' });
      return;
    }

    try {
      await importMutation.mutateAsync({
        file,
        onProgress: (loaded: number, total?: number) => helpers?.reportProgress(loaded, total),
      });
      toast('Import successful', { variant: 'success' });
      setFile(null);
    } catch (error) {
      logClientError(error);
      toast(error instanceof Error ? error.message : 'Import failed', { variant: 'error' });
    }
  };

  return (
    <div className='space-y-6'>
      <PanelHeader title='Import Products from CSV' />
      <div className='flex w-full max-w-sm items-center space-x-2'>
        <FileUploadButton
          onFilesSelected={(files: File[]) => handleFileChange(files)}
          accept='.csv'
        >
          Choose CSV
        </FileUploadButton>
        <Button
          onClick={() => {
            void handleSubmit();
          }}
          disabled={importMutation.isPending}
        >
          {importMutation.isPending ? 'Importing...' : 'Import'}
        </Button>
      </div>
    </div>
  );
};

