export function ImportLastResultSection(): React.JSX.Element | null {
  const { lastResult, activeImportRunId, activeImportRun } = useImportExportData();

  if (!lastResult) return null;

  const activeRun = activeImportRun?.run ?? null;
  const effectiveResult = React.useMemo(
    () => resolveLiveImportResult(lastResult, activeRun),
    [activeRun, lastResult]
  );
  const displaySummary = getImportResultDisplaySummary(effectiveResult);
  const runFailure =
    activeRun?.id === effectiveResult.runId
      ? {
          errorCode: activeRun.errorCode ?? null,
          error: activeRun.error ?? null,
        }
      : null;
  const directTargetLabel =
    activeRun?.id === effectiveResult.runId && activeRun?.params?.directTarget
      ? activeRun.params.directTarget.type === 'sku'
        ? `SKU ${activeRun.params.directTarget.value}`
        : `Base Product ID ${activeRun.params.directTarget.value}`
      : null;

  return (
    <FormSection title='Last import summary' className='p-4'>
      <div className='flex items-center gap-2 mt-1'>
        <span className='text-sm text-gray-300'>Run {effectiveResult.runId} is</span>
        <StatusBadge status={effectiveResult.status} className='font-bold' />
      </div>
      {effectiveResult.summaryMessage ? (
        <p className='mt-1 text-xs text-gray-400'>{effectiveResult.summaryMessage}</p>
      ) : null}
      <div className='mt-2 space-y-1 text-xs text-gray-400'>
        <p>
          Dispatch mode:{' '}
          <span className='font-mono text-gray-200'>{displaySummary.dispatchModeLabel}</span>
        </p>
        <p>
          Queue job: <span className='font-mono text-gray-200'>{displaySummary.queueJobLabel}</span>
        </p>
        {directTargetLabel ? (
          <p>
            Exact target: <span className='font-mono text-cyan-200'>{directTargetLabel}</span>
          </p>
        ) : null}
        <div className='flex flex-wrap items-center gap-x-3 gap-y-1 pt-1'>
          <Link
            href={`/admin/ai-paths/queue?tab=product-imports&query=${encodeURIComponent(effectiveResult.runId)}`}
            className='text-cyan-300 hover:text-cyan-200'
          >
            View in Runtime Queue
          </Link>
          <Link
            href={`/api/v2/integrations/imports/base/runs/${encodeURIComponent(effectiveResult.runId)}?includeItems=true&page=1&pageSize=250`}
            target='_blank'
            rel='noopener noreferrer'
            className='text-gray-300 hover:text-white'
          >
            Open JSON detail
          </Link>
        </div>
      </div>
      {displaySummary.explanation ? (
        <p className='mt-2 text-xs text-amber-300'>{displaySummary.explanation}</p>
      ) : null}
      {directTargetLabel ? (
        <p className='mt-1 text-xs text-cyan-300'>
          Exact target runs always create a new product and attach a Base.com connection to it.
        </p>
      ) : null}
      {runFailure?.errorCode || runFailure?.error ? (
        <div className='mt-3 rounded-md border border-rose-500/30 bg-rose-950/20 p-3'>
          <p className='text-[11px] font-semibold uppercase tracking-wider text-rose-200'>
            Latest failure
          </p>
          <div className='mt-2 space-y-1 text-xs text-gray-300'>
            {runFailure.errorCode ? (
              <p>
                Error code: <span className='font-mono text-rose-200'>{runFailure.errorCode}</span>
              </p>
            ) : null}
            {runFailure.error ? <p>{runFailure.error}</p> : null}
          </div>
        </div>
      ) : null}
      {(effectiveResult.preflight?.issues?.length ?? 0) > 0 ? (
        <div className='mt-3 space-y-1 text-xs text-gray-400'>
          {effectiveResult.preflight?.issues?.map((issue: BaseImportPreflightIssue, index: number) => (
            <p key={`${issue.code}-${index}`}>• {issue.message}</p>
          ))}
        </div>
      ) : null}
      {activeImportRunId ? (
        <Hint className='mt-2 font-mono'>Active run: {activeImportRunId}</Hint>
      ) : null}
    </FormSection>
  );
}

import type {
  BaseImportItemRecord,
  BaseImportRunRecord,
  BaseImportParameterImportSummary,
  BaseImportRunParameterImportSummary,
} from '@/shared/contracts/integrations/base-com';

const DEFAULT_PARAMETER_IMPORT_SUMMARY: BaseImportRunParameterImportSummary = {
  itemsApplied: 0,
  extracted: 0,
  resolved: 0,
  created: 0,
  written: 0,
};

export type ImportRunCustomFieldMetadata = {
  seededFieldNames: string[];
  autoMatchedFieldNames: string[];
  explicitMappedFieldNames: string[];
  skippedFieldNames: string[];
  overriddenFieldNames: string[];
};

export type ImportRunCustomFieldSummary = {
  itemsApplied: number;
  seeded: number;
  autoMatched: number;
  explicitMapped: number;
  skipped: number;
  overridden: number;
};

const readStringList = (value: unknown): string[] => {
  if (!Array.isArray(value)) {
    return [];
  }

  return Array.from(
    new Set(
      value
        .filter((entry: unknown): entry is string => typeof entry === 'string')
        .map((entry: string): string => entry.trim())
        .filter((entry: string): boolean => entry.length > 0)
    )
  ).sort((left: string, right: string) => left.localeCompare(right));
};

const getItemCustomFieldImportMetadata = (
  item: BaseImportItemRecord
): ImportRunCustomFieldMetadata | null => {
  const metadata = item.metadata;
  if (!metadata || typeof metadata !== 'object') {
    return null;
  }

  const rawCustomFieldImport = metadata['customFieldImport'];
  if (!rawCustomFieldImport || typeof rawCustomFieldImport !== 'object') {
    return null;
  }

  const customFieldImport = rawCustomFieldImport as Record<string, unknown>;
  return {
    seededFieldNames: readStringList(customFieldImport['seededFieldNames']),
    autoMatchedFieldNames: readStringList(customFieldImport['autoMatchedFieldNames']),
    explicitMappedFieldNames: readStringList(customFieldImport['explicitMappedFieldNames']),
    skippedFieldNames: readStringList(customFieldImport['skippedFieldNames']),
    overriddenFieldNames: readStringList(customFieldImport['overriddenFieldNames']),
  };
};

const hasCustomFieldImportActivity = (
  metadata: ImportRunCustomFieldMetadata | null | undefined
): boolean =>
  Boolean(
    metadata &&
      (
        metadata.seededFieldNames.length > 0 ||
        metadata.autoMatchedFieldNames.length > 0 ||
        metadata.explicitMappedFieldNames.length > 0 ||
        metadata.skippedFieldNames.length > 0 ||
        metadata.overriddenFieldNames.length > 0
      )
  );

const normalizeParameterImportSummaryCount = (value: unknown): number => {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    return 0;
  }

  return Math.max(0, Math.floor(value));
};

const hasParameterImportSummaryActivity = (
  summary: BaseImportParameterImportSummary | BaseImportRunParameterImportSummary | null | undefined
): boolean => {
  if (!summary) {
    return false;
  }

  return (
    summary.extracted > 0 || summary.resolved > 0 || summary.created > 0 || summary.written > 0
  );
};

const getItemCompletionTimestamp = (item: BaseImportItemRecord): number => {
  const parsed = Date.parse(item.finishedAt ?? item.updatedAt ?? '');
  return Number.isFinite(parsed) ? parsed : Number.NaN;
};

export const hasRetryableImportItems = (items: BaseImportItemRecord[]): boolean =>
  items.some((item: BaseImportItemRecord) => item.status === 'failed' || item.status === 'pending');

export const getImportRunErrorItems = (
  items: BaseImportItemRecord[],
  limit = 10
): BaseImportItemRecord[] => {
  return items
    .filter((item: BaseImportItemRecord) => item.status === 'failed' || Boolean(item.errorMessage))
    .sort(compareImportItemsByLatestCompletion)
    .slice(0, limit);
};

export const buildParameterImportSummaryFromItems = (
  items: BaseImportItemRecord[]
): BaseImportRunParameterImportSummary | null => {
  const aggregated = items.reduce(
    (
      acc: BaseImportRunParameterImportSummary,
      item: BaseImportItemRecord
    ): BaseImportRunParameterImportSummary => {
      const summary = item.parameterImportSummary;
      if (!summary) {
        return acc;
      }

      return {
        itemsApplied: acc.itemsApplied + 1,
        extracted: acc.extracted + normalizeParameterImportSummaryCount(summary.extracted),
        resolved: acc.resolved + normalizeParameterImportSummaryCount(summary.resolved),
        created: acc.created + normalizeParameterImportSummaryCount(summary.created),
        written: acc.written + normalizeParameterImportSummaryCount(summary.written),
      };
    },
    DEFAULT_PARAMETER_IMPORT_SUMMARY
  );

  return hasParameterImportSummaryActivity(aggregated) || aggregated.itemsApplied > 0
    ? aggregated
    : null;
};

export const resolveImportRunParameterImportSummary = (
  runSummary: BaseImportRunParameterImportSummary | null | undefined,
  items: BaseImportItemRecord[]
): BaseImportRunParameterImportSummary | null => {
  if (hasParameterImportSummaryActivity(runSummary) || (runSummary?.itemsApplied ?? 0) > 0) {
    return runSummary ?? null;
  }

  if (items.length === 0) {
    return null;
  }

  return buildParameterImportSummaryFromItems(items);
};

export const buildCustomFieldImportSummaryFromItems = (
  items: BaseImportItemRecord[]
): ImportRunCustomFieldSummary | null => {
  let itemsApplied = 0;
  const seededFieldNames = new Set<string>();
  const autoMatchedFieldNames = new Set<string>();
  const explicitMappedFieldNames = new Set<string>();
  const skippedFieldNames = new Set<string>();
  const overriddenFieldNames = new Set<string>();

  items.forEach((item: BaseImportItemRecord): void => {
    const metadata = getItemCustomFieldImportMetadata(item);
    if (!metadata || !hasCustomFieldImportActivity(metadata)) {
      return;
    }

    itemsApplied += 1;
    metadata.seededFieldNames.forEach((fieldName: string): void => {
      seededFieldNames.add(fieldName);
    });
    metadata.autoMatchedFieldNames.forEach((fieldName: string): void => {
      autoMatchedFieldNames.add(fieldName);
    });
    metadata.explicitMappedFieldNames.forEach((fieldName: string): void => {
      explicitMappedFieldNames.add(fieldName);
    });
    metadata.skippedFieldNames.forEach((fieldName: string): void => {
      skippedFieldNames.add(fieldName);
    });
    metadata.overriddenFieldNames.forEach((fieldName: string): void => {
      overriddenFieldNames.add(fieldName);
    });
  });

  if (
    itemsApplied === 0 &&
    seededFieldNames.size === 0 &&
    autoMatchedFieldNames.size === 0 &&
    explicitMappedFieldNames.size === 0 &&
    skippedFieldNames.size === 0 &&
    overriddenFieldNames.size === 0
  ) {
    return null;
  }

  return {
    itemsApplied,
    seeded: seededFieldNames.size,
    autoMatched: autoMatchedFieldNames.size,
    explicitMapped: explicitMappedFieldNames.size,
    skipped: skippedFieldNames.size,
    overridden: overriddenFieldNames.size,
  };
};

export const compareImportItemsByLatestCompletion = (
  left: BaseImportItemRecord,
  right: BaseImportItemRecord
): number => {
  const leftTime = getItemCompletionTimestamp(left);
  const rightTime = getItemCompletionTimestamp(right);

  if (!Number.isFinite(leftTime) && !Number.isFinite(rightTime)) return 0;
  if (!Number.isFinite(leftTime)) return 1;
  if (!Number.isFinite(rightTime)) return -1;
  return rightTime - leftTime;
};

export const getParameterSyncHistoryItems = (
  items: BaseImportItemRecord[],
  limit = 8
): BaseImportItemRecord[] => {
  return items
    .filter((item: BaseImportItemRecord) => Boolean(item.parameterImportSummary))
    .sort(compareImportItemsByLatestCompletion)
    .slice(0, limit);
};

export const getCustomFieldImportHistoryItems = (
  items: BaseImportItemRecord[],
  limit = 8
): BaseImportItemRecord[] => {
  return items
    .filter((item: BaseImportItemRecord) =>
      hasCustomFieldImportActivity(getItemCustomFieldImportMetadata(item))
    )
    .sort(compareImportItemsByLatestCompletion)
    .slice(0, limit);
};

export const formatCustomFieldImportHistory = (item: BaseImportItemRecord): string | null => {
  const metadata = getItemCustomFieldImportMetadata(item);
  if (!metadata || !hasCustomFieldImportActivity(metadata)) {
    return null;
  }

  const segments: string[] = [];
  const append = (label: string, values: string[]): void => {
    if (values.length === 0) {
      return;
    }
    segments.push(`${label}: ${values.join(', ')}`);
  };

  append('seeded', metadata.seededFieldNames);
  append('auto', metadata.autoMatchedFieldNames);
  append('explicit', metadata.explicitMappedFieldNames);
  append('skipped', metadata.skippedFieldNames);
  append('overridden', metadata.overriddenFieldNames);

  return segments.length > 0 ? segments.join(' · ') : null;
};

export type ImportRunDispatchDiagnostics = {
  tone: 'info' | 'warning' | 'error';
  title: string;
  details: string[];
};

export type ImportRunRetryDiagnostics = {
  scheduledCount: number;
  nextRetryAt: string | null;
};

export const resolveImportRunDispatchDiagnostics = (
  run: BaseImportRunRecord | null
): ImportRunDispatchDiagnostics | null => {
  if (!run) {
    return null;
  }

  if (run.preflight && !run.preflight.ok) {
    return {
      tone: 'error',
      title: 'Dispatch stopped at preflight',
      details: [
        'This run did not reach the runtime queue because the preflight check failed.',
        ...run.preflight.issues.map((issue) => issue.message),
      ],
    };
  }

  if (run.dispatchMode == null && (run.stats?.total ?? 0) === 0 && run.status === 'completed') {
    return {
      tone: 'warning',
      title: 'No products matched the current import filters',
      details: ['Nothing was queued because item resolution returned zero import candidates.'],
    };
  }

  if (run.dispatchMode === 'inline') {
    return {
      tone: 'warning',
      title: 'This run used inline fallback instead of BullMQ',
      details: [
        'Base imports use the separate base-import runtime queue.',
        'This run executed inline because Redis queueing was unavailable or enqueueing failed.',
      ],
    };
  }

  return null;
};

export const resolveImportRunRetryDiagnostics = (
  items: BaseImportItemRecord[]
): ImportRunRetryDiagnostics | null => {
  const scheduledRetryItems = items.filter(
    (item: BaseImportItemRecord): boolean =>
      item.status === 'pending' && item.retryable === true && typeof item.nextRetryAt === 'string'
  );

  if (scheduledRetryItems.length === 0) {
    return null;
  }

  const nextRetryAt =
    scheduledRetryItems
      .map((item: BaseImportItemRecord) => {
        const parsed = Date.parse(item.nextRetryAt ?? '');
        return Number.isFinite(parsed) ? parsed : Number.NaN;
      })
      .filter((value: number) => Number.isFinite(value))
      .sort((left: number, right: number) => left - right)[0] ?? Number.NaN;

  return {
    scheduledCount: scheduledRetryItems.length,
    nextRetryAt: Number.isFinite(nextRetryAt) ? new Date(nextRetryAt).toISOString() : null,
  };
};

import { PRODUCT_PARAMETER_TARGET_PREFIX } from '@/features/data-import-export/components/imports/constants';
import type { ParameterReference as ParsedParameterTarget } from '@/shared/contracts/integrations/parameter-reference';

export type { ParsedParameterTarget };

export const parseParameterTarget = (value: string): ParsedParameterTarget | null => {
  const trimmed = value.trim();
  if (!trimmed) return null;
  if (!trimmed.toLowerCase().startsWith(PRODUCT_PARAMETER_TARGET_PREFIX)) {
    return null;
  }

  const payload = trimmed.slice(PRODUCT_PARAMETER_TARGET_PREFIX.length).trim();
  if (!payload) return null;

  const languageDelimiterIndex = payload.indexOf('|');
  if (languageDelimiterIndex < 0) {
    return {
      parameterId: payload,
      languageCode: null,
    };
  }

  const parameterId = payload.slice(0, languageDelimiterIndex).trim();
  if (!parameterId) return null;
  const languageCode = payload.slice(languageDelimiterIndex + 1).trim();
  if (!languageCode) return null;
  return {
    parameterId,
    languageCode: languageCode.toLowerCase(),
  };
};

export const toParameterTargetValue = (parameterId: string): string =>
  `${PRODUCT_PARAMETER_TARGET_PREFIX}${parameterId}`.toLowerCase();

export const getParameterDisplayName = (parameter: {
  id: string;
  name_en?: string | null;
  name_pl?: string | null;
  name_de?: string | null;
}): string =>
  parameter.name_en?.trim() ||
  parameter.name_pl?.trim() ||
  parameter.name_de?.trim() ||
  parameter.id.trim();

import type { ImageRetryPreset } from '@/shared/contracts/integrations/base';

const clonePreset = (preset: ImageRetryPreset): ImageRetryPreset => ({
  ...preset,
  transform: { ...preset.transform },
});

export const DEFAULT_IMAGE_RETRY_PRESETS: ImageRetryPreset[] = [
  {
    id: 'lower-dimension',
    name: 'Lower max dimension (1200px)',
    description: 'Resize down to 1200px and convert to JPEG.',
    imageBase64Mode: 'base-only' as const,
    transform: { forceJpeg: true, maxDimension: 1200, jpegQuality: 85, width: 1200, height: 1200 },
  },
  {
    id: 'lower-quality',
    name: 'Lower JPEG quality (70)',
    description: 'Compress harder without resizing.',
    imageBase64Mode: 'base-only' as const,
    transform: { forceJpeg: true, jpegQuality: 70 },
  },
  {
    id: 'lower-both',
    name: 'Lower dimension + quality (1200px, 70)',
    description: 'Resize and compress for maximum compatibility.',
    imageBase64Mode: 'base-only' as const,
    transform: { forceJpeg: true, maxDimension: 1200, jpegQuality: 70, width: 1200, height: 1200 },
  },
].map(clonePreset);

export const getDefaultImageRetryPresets = (): ImageRetryPreset[] =>
  DEFAULT_IMAGE_RETRY_PRESETS.map(clonePreset);

export const buildImageRetryPresetLabel = (preset: ImageRetryPreset): string => {
  const { maxDimension, jpegQuality } = preset.transform;
  const dim = maxDimension ?? 'auto';
  const qual = jpegQuality ?? 'auto';

  if (preset.id === 'lower-dimension') return `Lower max dimension (${dim}px)`;
  if (preset.id === 'lower-quality') return `Lower JPEG quality (${qual})`;
  if (preset.id === 'lower-both') return `Lower dimension + quality (${dim}px, ${qual})`;

  return preset.name.trim() !== '' ? preset.name.trim() : 'Image retry preset';
};

export const buildImageRetryPresetDescription = (preset: ImageRetryPreset): string => {
  const { maxDimension, jpegQuality } = preset.transform;
  const dimLabel = maxDimension !== null && maxDimension !== undefined ? `${maxDimension}px` : 'your target size';
  const qualLabel = jpegQuality !== null && jpegQuality !== undefined ? jpegQuality : 'your';

  if (preset.id === 'lower-dimension') return `Resize down to ${dimLabel} and convert to JPEG.`;
  if (preset.id === 'lower-quality') return `Compress to quality ${qualLabel} without resizing.`;
  if (preset.id === 'lower-both') return `Resize to ${dimLabel} and compress to ${qualLabel} for maximum compatibility.`;

  return preset.description.trim() !== '' ? preset.description.trim() : 'Adjust image export settings.';
};

export const withImageRetryPresetLabels = (preset: ImageRetryPreset): ImageRetryPreset => ({
  ...preset,
  name: buildImageRetryPresetLabel(preset),
  description: buildImageRetryPresetDescription(preset),
});

const normalizePreset = (
  entry: unknown,
  byId: Map<string, ImageRetryPreset>
): ImageRetryPreset | null => {
  if (entry === null || typeof entry !== 'object') return null;
  const record = entry as Partial<ImageRetryPreset> & {
    transform?: Partial<ImageRetryPreset['transform']>;
    label?: string;
  };
  const id = typeof record.id === 'string' ? record.id : null;
  if (id === null) return null;
  const fallback = byId.get(id);

  const name =
    typeof record.name === 'string' && record.name.trim() !== ''
      ? record.name
      : typeof record.label === 'string' && record.label.trim() !== ''
        ? record.label
        : (fallback?.name ?? 'Image retry preset');

  const description =
    typeof record.description === 'string' && record.description.trim() !== ''
      ? record.description
      : (fallback?.description ?? 'Adjust image export settings.');

  const preset: ImageRetryPreset = {
    id,
    name,
    description,
    imageBase64Mode: record.imageBase64Mode ?? fallback?.imageBase64Mode ?? 'base-only',
    transform: {
      ...(fallback?.transform ?? {}),
      ...(record.transform ?? {}),
    },
  };
  return withImageRetryPresetLabels(preset);
};

export const normalizeImageRetryPresets = (value: unknown): ImageRetryPreset[] => {
  if (!Array.isArray(value) || value.length === 0) {
    return getDefaultImageRetryPresets();
  }
  const defaults = getDefaultImageRetryPresets();
  const byId = new Map(defaults.map((p) => [p.id, p]));
  const normalized = value
    .map((v) => normalizePreset(v, byId))
    .filter((p): p is ImageRetryPreset => p !== null);

  return normalized.length > 0 ? normalized : defaults;
};

import type {
  BaseImportPreflightIssue,
  BaseImportRunRecord,
} from '@/shared/contracts/integrations/base-com';
import type { ImportResponse } from '@/shared/contracts/integrations/import-export';
import type { ToastOptions } from '@/shared/contracts/ui/base';

type ImportActionKind = 'import' | 'resume';

export type ImportResultDisplaySummary = {
  dispatchModeLabel: string;
  queueJobLabel: string;
  explanation: string | null;
};

const getPreflightErrorMessages = (result: ImportResponse): string[] =>
  (result.preflight?.issues ?? [])
    .filter((issue: BaseImportPreflightIssue) => issue.severity === 'error')
    .map((issue: BaseImportPreflightIssue) => issue.message);

export const buildImportResponseFromRun = (run: BaseImportRunRecord): ImportResponse => ({
  runId: run.id,
  status: run.status,
  preflight: run.preflight ?? null,
  queueJobId: run.queueJobId ?? null,
  dispatchMode: run.dispatchMode ?? null,
  summaryMessage: run.summaryMessage ?? null,
});

export const resolveLiveImportResult = (
  lastResult: ImportResponse,
  activeRun: BaseImportRunRecord | null | undefined
): ImportResponse => {
  if (activeRun?.id !== lastResult.runId) {
    return lastResult;
  }

  return {
    ...lastResult,
    ...buildImportResponseFromRun(activeRun),
  };
};

export const areImportResponsesEquivalent = (
  left: ImportResponse | null,
  right: ImportResponse | null
): boolean => {
  if (left === right) return true;
  if (left === null || right === null) return false;

  return (
    left.runId === right.runId &&
    left.status === right.status &&
    left.queueJobId === right.queueJobId &&
    left.dispatchMode === right.dispatchMode &&
    left.summaryMessage === right.summaryMessage &&
    JSON.stringify(left.preflight ?? null) === JSON.stringify(right.preflight ?? null)
  );
};

const getDispatchModeLabel = (dispatchMode: string | null): string => {
  if (dispatchMode === 'queued') return 'queued (base-import runtime queue)';
  if (dispatchMode === 'inline') return 'inline fallback';
  return 'not dispatched';
};

export const getImportResultDisplaySummary = (
  result: ImportResponse
): ImportResultDisplaySummary => {
  const isExactTargetSummary = (result.summaryMessage?.startsWith('Queued exact ') ?? false);
  const dispatchModeLabel = getDispatchModeLabel(result.dispatchMode);
  const queueJobLabel = result.queueJobId ?? 'not assigned';

  if (result.preflight?.ok === false) {
    return {
      dispatchModeLabel,
      queueJobLabel,
      explanation: 'Dispatch stopped at preflight before this run reached runtime queueing.',
    };
  }

  if (result.dispatchMode === 'inline') {
    return {
      dispatchModeLabel,
      queueJobLabel,
      explanation: 'This run used inline fallback because Redis queueing was unavailable or enqueueing failed.',
    };
  }

  if (result.dispatchMode === 'queued') {
    return {
      dispatchModeLabel,
      queueJobLabel,
      explanation: isExactTargetSummary
        ? 'This exact-target run was submitted to the separate base-import runtime queue and will create a new product with a Base.com connection.'
        : 'This run was submitted to the separate base-import runtime queue.',
    };
  }

  const isMatchedEmpty = (result.status === 'completed' || result.status === 'partial_success') &&
    (result.summaryMessage?.includes('No products matched') ?? false);

  if (isMatchedEmpty) {
    return {
      dispatchModeLabel,
      queueJobLabel,
      explanation: 'Nothing was queued because item resolution returned zero import candidates.',
    };
  }

  return {
    dispatchModeLabel,
    queueJobLabel,
    explanation: null,
  };
};

const getImportLabel = (kind: ImportActionKind, dryRun: boolean, isExact: boolean): string => {
  if (kind === 'resume') return 'Import resume';
  if (isExact) return 'Exact import';
  if (dryRun) return 'Dry-run import';
  return 'Import';
};

export const buildImportResultToast = (
  result: ImportResponse,
  options: { kind: ImportActionKind; dryRun?: boolean }
): { message: string; toast: ToastOptions } => {
  const isExactTarget = (result.summaryMessage?.startsWith('Queued exact ') ?? false);
  const label = getImportLabel(options.kind, options.dryRun ?? false, isExactTarget);

  if (result.status === 'queued' || result.status === 'running') {
    const suffix = result.queueJobId !== null ? ` (job ${result.queueJobId}).` : '.';
    const msg = result.dispatchMode === 'inline' 
      ? `${label} running inline${suffix}` 
      : `${label} queued to base-import runtime${suffix}`;

    return {
      message: msg,
      toast: { variant: result.dispatchMode === 'inline' ? 'warning' : 'success' },
    };
  }

  if (result.status === 'completed' || result.status === 'partial_success') {
    return {
      message: result.summaryMessage ?? `${label} completed.`,
      toast: { variant: 'success' },
    };
  }

  if (result.status === 'failed') {
    const preflightErrors = getPreflightErrorMessages(result);
    if (preflightErrors.length > 0) {
      return {
        message: `Import blocked before dispatch: ${preflightErrors[0]}`,
        toast: { variant: 'error' },
      };
    }

    return {
      message: result.summaryMessage ?? `${label} failed.`,
      toast: { variant: 'error' },
    };
  }

  return {
    message: result.summaryMessage ?? `${label} updated.`,
    toast: { variant: 'info' },
  };
};
